import json
from jsonschema import validate, ValidationError
import uuid
from typing import Callable, Dict, Any, Type

class JSONSerializable:
    def to_json(self) -> str:
        """
        Converts the object to a JSON string.
        """
        try:
            return json.dumps(self.__dict__, indent=4)
        except TypeError as e:
            raise ValueError("Object cannot be serialized to JSON") from e

    @classmethod
    def from_json(cls, json_str: str, schema: dict) -> 'JSONSerializable':
        """
        Creates a new instance of the class from a JSON string, validating against a schema.
        """
        try:
            data = json.loads(json_str)
            validate(instance=data, schema=schema)
            return cls(**data)
        except (json.JSONDecodeError, ValidationError, TypeError, ValueError) as e:
            raise ValueError("Invalid JSON string or data") from e

class JSONObjectFactoryRegistry:
    _registry: Dict[str, Callable[[], Type[JSONSerializable]]] = {}

    @staticmethod
    def register_factory(factory_id: str, factory_function: Callable[[], Type[JSONSerializable]]) -> None:
        if not isinstance(factory_id, str):
            raise TypeError("Factory ID must be a string")
        if not callable(factory_function):
            raise TypeError("Factory function must be callable")
        if not issubclass(factory_function(), JSONSerializable):
            raise ValueError("Factory function must return a subclass of JSONSerializable")

        if factory_id in JSONObjectFactoryRegistry._registry:
            raise ValueError(f"Factory ID '{factory_id}' already exists")

        JsonObjectFactoryRegistry._registry[factory_id] = factory_function

    @staticmethod
    def create_object(factory_id: str) -> JSONSerializable:
        if not isinstance(factory_id, str):
            raise TypeError("Factory ID must be a string")

        factory_function = JSONObjectFactoryRegistry._registry.get(factory_id)
        if factory_function is None:
            raise ValueError(f"Factory ID '{factory_id}' not found")

        try:
            return factory_function()
        except TypeError as e:
            raise TypeError(f"Error creating object with factory ID '{factory_id}': {e}") from e
        except ValueError as e:
            raise ValueError(f"Error creating object with factory ID '{factory_id}': {e}") from e

class MyData(JSONSerializable):
    def __init__(self, name: str, value: int):
        self.name = name
        self.value = value

class AnotherData(JSONSerializable):
    def __init__(self, description: str, enabled: bool):
        self.description = description
        self.enabled = enabled

def add_factory_function(factory_id: str, factory_function: Callable[[], Type[JSONSerializable]]) -> None:
    JsonObjectFactoryRegistry.register_factory(factory_id, factory_function)

def create_object_from_factory(factory_id: str) -> JSONSerializable:
    return JSONObjectFactoryRegistry.create_object(factory_id)

