# Configure logging
logging.basicConfig(filename='packet_log.txt', level=logging.INFO,
                    format='%(asctime)s - %(message)s')

COMMON_PORTS = [21, 22, 23, 25, 53, 80, 110, 111, 135, 139, 143, 443, 445, 993, 995, 1723, 3306, 3389, 5900, 8080]
ACTIONS = ['accept', 'deny', 'drop', 'reject']
IP_RANGE_START = os.environ.get('IP_RANGE_START', '192.168.1.1')
IP_RANGE_END = os.environ.get('IP_RANGE_END', '192.168.1.254')
PROTOCOLS = ['TCP', 'UDP', 'ICMP']

def generate_random_ip(start_ip, end_ip):
    """Generates a random IP address within the specified range."""
    try:
        start = ipaddress.ip_address(start_ip)
        end = ipaddress.ip_address(end_ip)
        random_ip_int = random.randint(int(start), int(end))
        random_ip = ipaddress.ip_address(random_ip_int)
        return str(random_ip)
    except ValueError as e:
        logging.error(f"Invalid IP address range: {e}")
        return None

def generate_random_port():
    """Generates a random port number from the common ports list."""
    return secrets.choice(COMMON_PORTS)

def generate_random_protocol():
    """Generates a random protocol from the list of protocols."""
    return secrets.choice(PROTOCOLS)

def generate_random_action():
    """Generates a random action from the list of actions."""
    return secrets.choice(ACTIONS)

def log_packet(protocol, src_ip, dest_ip, src_port, dest_port, action):
    """Logs the packet details to the log file."""
    try:
        log_message = f"Protocol: {protocol}, Source IP: {src_ip}, Destination IP: {dest_ip}, Source Port: {src_port}, Destination Port: {dest_port}, Action: {action}"
        logging.info(log_message)
    except IOError as e:
        logging.error(f"IOError logging packet: {e}")
    except PermissionError as e:
        logging.error(f"PermissionError logging packet: {e}")
    except Exception as e:
        logging.error(f"Error logging packet: {e}")

def main():
    """Main function to generate and log packets indefinitely."""
    while True:
        protocol = generate_random_protocol()
        src_ip = generate_random_ip(IP_RANGE_START, IP_RANGE_END)
        if src_ip is None:
            continue
        dest_ip = generate_random_ip(IP_RANGE_START, IP_RANGE_END)
        if dest_ip is None:
            continue
        src_port = generate_random_port()
        dest_port = generate_random_port()
        action = generate_random_action()

        log_packet(protocol, src_ip, dest_ip, src_port, dest_port, action)

        time.sleep(secrets.uniform(0.1, 1.0))  # Random interval between 0.1 and 1 second

if __name__ == "__main__":
