def is_valid_url(url):
    """
    Validates a URL to ensure it's properly formatted and returns an expected content type.
    """
    try:
        result = requests.get(url, stream=True, timeout=5, headers={'User-Agent': secrets.get_random_string(15)})
        if result.status_code == 200:
            content_type = result.headers.get('Content-Type', '').lower()
            if 'application/xml' in content_type or 'application/rss+xml' in content_type or 'application/atom+xml' in content_type:
                return True
            else:
                logging.warning(f"Unexpected Content-Type: {content_type} for {url}")
                return False
        else:
            return False
    except requests.exceptions.RequestException:
        return False

def sanitize_url(url):
    """
    Sanitizes a URL to prevent potential injection attacks.
    """
    if not isinstance(url, str):
        raise TypeError("URL must be a string.")
    try:
        result = urllib.parse.urlparse(url)
        if not all([result.scheme, result.netloc]):
            raise ValueError("Invalid URL format.")
        if result.scheme not in ('http', 'https'):
            raise ValueError("URL must start with http or https")
        return urllib.parse.urlunparse(result)
    except Exception:
        raise ValueError("Invalid URL")

def parse_feed(url, max_retries=3):
    """
    Parses a feed from a URL, retrying on failure with a random delay.
    """
    for attempt in range(max_retries):
        try:
            feed = feedparser.parse(url, request_headers={'User-Agent': secrets.get_random_string(15)})
            if feed.bozo == 1:
                logging.warning(f"Feed parsing error for {url}: {feed.bozo_exception}")
                return None
            if feed.entries:
                return feed
            else:
                logging.warning(f"No entries found in feed for {url}")
                return None
        except FeedParserDict as e:
            logging.error(f"FeedParserDict error parsing feed for {url}: {e}")
            if attempt < max_retries - 1:
                delay = random.uniform(1, 5)
                logging.info(f"Retrying in {delay:.2f} seconds...")
                time.sleep(delay)
            else:
                logging.error(f"Failed to parse feed for {url} after multiple retries.")
                return None
        except Exception as e:
            logging.error(f"Error parsing feed for {url}: {e}")
            if attempt < max_retries - 1:
                delay = random.uniform(1, 5)
                logging.info(f"Retrying in {delay:.2f} seconds...")
                time.sleep(delay)
            else:
                logging.error(f"Failed to parse feed for {url} after multiple retries.")
                return None
    return None

def process_urls(urls):
    """
    Iterates over a list of URLs, checks for valid feeds, and prints the data.
    """
    if not isinstance(urls, list):
        raise TypeError("URLs must be a list.")

    for url in urls:
        try:
            sanitized_url = sanitize_url(url)
            if is_valid_url(sanitized_url):
                feed = parse_feed(sanitized_url)
