import scipy.stats as stats
import inspect

def find_best_shape_parameter(data, distribution_name):
    valid_distributions = ["expon", "gamma", "uniform"]
    try:
        # Input validation: Ensure data is a list or numpy array
        if not isinstance(data, (list, np.ndarray)):
            raise TypeError("Data must be a list or numpy array.")

        # Input validation: Ensure data is numeric
        data = np.array(data, dtype=float)
        if not np.issubdtype(data.dtype, np.number):
            raise ValueError("Data must be numeric.")

        # Input validation: Sanitize distribution name
        if not isinstance(distribution_name, str):
            raise TypeError("Distribution name must be a string.")
        distribution_name = distribution_name.strip()
        if not distribution_name:
            raise ValueError("Distribution name cannot be empty.")

        if distribution_name not in valid_distributions:
            raise ValueError("Invalid distribution name. Supported distributions are: " + ", ".join(valid_distributions))

        # Get the distribution class
        try:
            dist = getattr(stats, distribution_name)
        except AttributeError:
            return None

        # Check if the distribution has default location and scale parameters of 0.0 and 1.0
        sig = inspect.signature(dist.ppf)
        params = sig.parameters
        has_loc = 'loc' in params
        has_scale = 'scale' in params

        if has_loc and has_scale:
            return None # Not a one-parameter family

        # Define a range of shape parameters to test
        if distribution_name == "expon":
            shape_values = np.linspace(0.1, 10, 50)
        elif distribution_name == "gamma":
            shape_values = np.linspace(0.1, 10, 50)
        elif distribution_name == "uniform":
            shape_values = np.linspace(1, 10, 50)
        else:
            return None

        # Calculate the probability plot correlation coefficient for each shape parameter
        correlation_coefficients = []
        for shape in shape_values:
            try:
                ppf_func = getattr(stats, distribution_name).ppf
                probabilities = stats.probplot(data, dist=dist, distargs=(shape,))[0]
                correlation_coefficient = np.corrcoef(data, probabilities)[0, 1]
                correlation_coefficients.append(correlation_coefficient)
            except Exception as e:
                print(f"Error during shape parameter {shape}: {e}")
                correlation_coefficients.append(-1.0)  # Assign a low value to indicate failure

        # Find the shape parameter that maximizes the correlation coefficient
        best_shape = shape_values[np.argmax(correlation_coefficients)]

        return best_shape

    except (TypeError, ValueError) as e:
        print(f"Input error: {e}")
        return None
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return None

