                    arg1 = float(args[0])
                    arg2 = float(args[1])
                except ValueError:
                    raise ValueError("Arguments for command1 must be numeric")
                minimizer.command1(arg1, arg2)

            elif command_name == "command2":
                if len(args) != 1:
                    raise ValueError("command2 requires 1 argument")
                try:
                    arg1 = float(args[0])
                except ValueError:
                    raise ValueError("Argument for command2 must be numeric")
                minimizer.command2(arg1)

            elif command_name == "command3":
                if len(args) != 0:
                    raise ValueError("command3 requires no arguments")
                minimizer.command3()

            else:
                raise ValueError(f"Unknown command: {command_name}")

    except Exception as e:
        parameters = minimizer.parameters
        chi2 = minimizer.chi2
        ndf = minimizer.ndf
        normalizedChi2 = minimizer.normalizedChi2
        raise e
    return parameters, chi2, ndf, normalizedChi2

