import psycopg2.extensions
import os

def create_db_and_user(db_name, owner_username=None):
    try:
        if not isinstance(db_name, str):
            raise TypeError("db_name must be a string")
        if not db_name:
            raise ValueError("db_name cannot be empty")
        if owner_username is not None and not isinstance(owner_username, str):
            raise TypeError("owner_username must be a string")

        conn = psycopg2.connect(
            host=os.environ.get("PGHOST", "localhost"),
            port=os.environ.get("PGPORT", 5432),
            user=os.environ.get("PGUSER", "postgres"),
            password=os.environ.get("PGPASSWORD", ""),
            database=os.environ.get("PGDATABASE", "postgres")
        )
        conn.autocommit = True

        cur = conn.cursor()

        try:
            cur.execute("CREATE DATABASE %s", (db_name,))
        except psycopg2.errors.DuplicateDatabase:
            print(f"Database {db_name} already exists.")
            return False
        except Exception as e:
            print(f"Error creating database: {e}")
            return False

        if owner_username:
            try:
                cur.execute("ALTER DATABASE %s OWNER TO %s", (db_name, owner_username))
            except psycopg2.errors.RoleNotFound:
                print(f"User {owner_username} not found.")
                return False
            except Exception as e:
                print(f"Error setting database owner: {e}")
                return False

        cur.close()
        conn.close()
        return True

    except (TypeError, ValueError) as e:
        print(f"Input validation error: {e}")
        return False
    except psycopg2.Error as e:
        print(f"PostgreSQL error: {e}")
        return False
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return False

