def get_jwt_token(token_file_path):
    """
    Retrieves a JWT token from a JSON file.

    Args:
        token_file_path (str): The path to the JSON file containing the JWT token.

    Returns:
        tuple: A tuple containing the JWT token and its signature, or (None, None) if no token is found or an error occurs.
    """
    if not isinstance(token_file_path, str):
        return None, None

    if not token_file_path:
        return None, None

    try:
        abs_path = os.path.abspath(token_file_path)
        if os.path.exists(abs_path) and os.path.isfile(abs_path):
            with open(abs_path, 'r') as f:
                try:
                    token_data = json.load(f)
                    if isinstance(token_data, dict) and len(token_data) == 2:
                        token = token_data.get('token')
                        signature = token_data.get('signature')
                        if isinstance(token, str) and isinstance(signature, str):
                            if len(token) > 0 and len(signature) > 0:
                                return token, signature
                            else:
                                return None, None
                        else:
                            return None, None
                    else:
                        return None, None
                except json.JSONDecodeError:
                    return None, None
        else:
            return None, None
    except Exception as e:
        return None, None

