def execute_command(command, args=None):
    """
    Executes a command using subprocess and returns the output.

    Args:
        command (str): The command to execute.
        args (list, optional): A list of arguments to pass to the command. Defaults to None.

    Returns:
        str: The output of the command, or an error message if the command fails.
    """
    try:
        if not isinstance(command, str):
            raise TypeError("Command must be a string.")
        if not re.match(r"^[a-zA-Z0-9_\-\.\/]+$", command):
            raise ValueError("Invalid command format. Only alphanumeric characters, underscores, hyphens, periods, and forward slashes are allowed.")

        if args:
            sanitized_args = [shlex.quote(str(arg)) for arg in args]
            process = subprocess.run([command] + sanitized_args, capture_output=True, text=True, check=True)
        else:
            process = subprocess.run([command], capture_output=True, text=True, check=True)

        return process.stdout
    except subprocess.CalledProcessError as e:
        return "Command failed."
    except FileNotFoundError:
        return "Command not found."
    except TypeError as e:
        return str(e)
    except ValueError as e:
        return str(e)
