CREATE OR REPLACE FUNCTION create_insert_drop_table(table_name TEXT, column_name TEXT, data_value TEXT)
RETURNS VOID AS $$
DECLARE
    sql_statement TEXT;
    log_prefix TEXT := 'create_insert_drop_table: ';
BEGIN
    -- Input Validation and Sanitization
    IF table_name IS NULL OR table_name = '' OR LENGTH(table_name) > 64 THEN
        RAISE EXCEPTION 'Invalid table name.';
    END IF;

    IF column_name IS NULL OR column_name = '' OR LENGTH(column_name) > 64 THEN
        RAISE EXCEPTION 'Invalid column name.';
    END IF;

    IF data_value IS NULL OR LENGTH(data_value) > 255 THEN
        RAISE EXCEPTION 'Invalid data value.';
    END IF;

    -- Create Table
    sql_statement := format('CREATE TEMP TABLE IF NOT EXISTS %I (id SERIAL PRIMARY KEY, %I TEXT);', table_name, column_name);
    EXECUTE sql_statement;

    -- Insert Data
    sql_statement := format('INSERT INTO %I (%I) VALUES (%L)', table_name, column_name, data_value);
    EXECUTE sql_statement;

    -- Drop Table
    sql_statement := format('DROP TABLE IF EXISTS %I;', table_name);
    EXECUTE sql_statement;

EXCEPTION
    WHEN OTHERS THEN
        -- Error Handling: Log the error (replace with proper logging mechanism)
        RAISE NOTICE '%Error: %', log_prefix, SQLERRM;
        -- Ensure table is dropped if creation failed
        BEGIN
            sql_statement := format('DROP TABLE IF EXISTS %I;', table_name);
            EXECUTE sql_statement;
        END;
        -- Re-raise the exception to signal failure
        RAISE;
END;
$$ LANGUAGE plpgsql;

