def secure_sum_with_condition(data, method):
    """
    Calculates the sum of values in a NumPy array based on a condition defined by a lambda function.

    Args:
        data (np.ndarray): The input NumPy array.
        method (str): A string representing the lambda function to apply.

    Returns:
        float: The sum of the values that satisfy the condition.

    Raises:
        TypeError: if data is not a NumPy array or method is not a string.
        ValueError: if the method string is invalid or contains unsafe code.
    """

    # Input validation and sanitization
    if not isinstance(data, np.ndarray):
        raise TypeError("Data must be a NumPy array.")
    if not isinstance(method, str):
        raise TypeError("Method must be a string.")

    if data.size > 10000:
        raise ValueError("Input array size exceeds the limit.")

    try:
        tree = ast.parse(method)

        class SafeEvaluator(object):
            def __init__(self):
                self.namespace = {}

            def eval(self, node):
                if isinstance(node, ast.Num):
                    return node.n
                elif isinstance(node, ast.Name):
                    if node.id in self.namespace:
                        return self.namespace[node.id]
                    else:
                        raise NameError(node.id)
                elif isinstance(node, ast.BinOp):
                    left = self.eval(node.left)
                    right = self.eval(node.right)
                    if isinstance(node.op, ast.Add):
                        return left + right
                    elif isinstance(node.op, ast.Sub):
                        return left - right
                    elif isinstance(node.op, ast.Mult):
                        return left * right
                    elif isinstance(node.op, ast.Div):
                        return left / right
                    else:
                        raise TypeError("Unsupported binary operator")
                elif isinstance(node, ast.UnaryOp):
                    operand = self.eval(node.operand)
                    if isinstance(node.op, ast.USub):
                        return -operand
                    elif isinstance(node.op, ast.UAdd):
                        return operand
                    else:
                        raise TypeError("Unsupported unary operator")
                elif isinstance(node, ast.Compare):
                    left = self.eval(node.left)
                    right = self.eval(node.comparators[0])
                    if isinstance(node.ops[0], ast.Eq):
                        return left == right
                    elif isinstance(node.ops[0], ast.NotEq):
                        return left != right
                    elif isinstance(node.ops[0], ast.Lt):
                        return left < right
                    elif isinstance(node.ops[0], ast.LtE):
                        return left <= right
                    elif isinstance(node.ops[0], ast.Gt):
                        return left > right
                    elif isinstance(node.ops[0], ast.GtE):
                        return left >= right
                    else:
                        raise TypeError("Unsupported comparison operator")
                elif isinstance(node, ast.BoolOp):
                    if isinstance(node.op, ast.And):
                        return self.eval(node.values[0]) and self.eval(node.values[1])
                    elif isinstance(node.op, ast.Or):
                        return self.eval(node.values[0]) or self.eval(node.values[1])
                    else:
                        raise TypeError("Unsupported boolean operator")
                elif isinstance(node, ast.Call):
                    if node.func.id not in ['len']:
                        raise TypeError("Unsupported function call")
                    args = [self.eval(arg) for arg in node.args]
                    if node.func.id == 'len' and len(args) != 1:
                        raise TypeError("len function requires one argument")
                    try:
                        return len(args[0]) if node.func.id == 'len' else None
                    except Exception:
                        raise TypeError("len function requires one argument")
                else:
                    raise TypeError("Unsupported node type")

        evaluator = SafeEvaluator()
        exclude_lambda = evaluator.eval(tree.body[0])

    except (SyntaxError, NameError, TypeError) as e:
        raise ValueError("Invalid method string: {}".format(e))
    except Exception as e:
        raise ValueError("Error evaluating method string: {}".format(e))

