def generate_random_data(prefix="string", maxlen=10, domen="example.com"):
    """
    Generates a random string, numbers, or email based on the input parameters.

    Args:
        prefix (str, optional): The type of data to generate ("string", "number", or "mail").
                                 Defaults to "string".
        maxlen (int, optional): The maximum length of the generated data. Defaults to 10.
        domen (str, optional): The domain for email generation. Defaults to "example.com".

