import urllib.request
import urllib.parse
import json
import getpass
import re
import requests
import time

class GitFetcher:
    def __init__(self, org_name, username, password):
        self.org_name = org_name
        self.username = username
        self.password = password

    def get_org_info(self):
        url = f"https://api.github.com/orgs/{self.org_name}"
        for attempt in range(3):
            try:
                response = requests.get(url, auth=(self.username, self.password), verify=True, timeout=10)
                response.raise_for_status()
                data = response.text
                json_data = json.loads(data)
                return json_data
            except requests.exceptions.HTTPError as e:
                if e.response.status_code == 401:
                    print("Authentication failed. Please check your username and password.")
                elif e.response.status_code == 404:
                    print(f"Organization '{self.org_name}' not found.")
                else:
                    print(f"HTTP Error: {e.response.status_code}")
                return None
            except requests.exceptions.RequestException as e:
                print(f"Request Error: {e}")
                if attempt < 2:
                    time.sleep(2 ** attempt)
                return None
            except json.JSONDecodeError as e:
                print(f"JSON Decode Error: {e}")
                return None
        return None

def validate_input(org_name, username, password):
    if not re.match(r"^[a-zA-Z0-9_-]+$", org_name):
        raise ValueError("Invalid organization name.  Must contain only alphanumeric characters, underscores, or hyphens.")
    if not re.match(r"^[a-zA-Z0-9]+$", username):
        raise ValueError("Invalid username. Must contain only alphanumeric characters.")
    if not password or len(password) < 8:
        raise ValueError("Password must be at least 8 characters long.")
    return org_name, username, password

def main():
    try:
        org_name = input("Enter the GitHub organization name: ")
        username = input("Enter your GitHub username: ")
        password = getpass.getpass("Enter your GitHub password: ")

        org_name, username, password = validate_input(org_name, username, password)

        fetcher = GitFetcher(org_name, username, password)
        org_info = fetcher.get_org_info()

        if org_info:
            print(json.dumps(org_info, indent=4))

    except ValueError as e:
        print(f"Input Error: {e}")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")

if __name__ == "__main__":
    main()

