import re
import os
import logging
import subprocess

logging.basicConfig(level=logging.INFO)

def execute_query(query_template, scope, parameters):
    """
    Executes a query template with provided parameters, ensuring security.

    Args:
        query_template (str): The query template string.
        scope (dict): A dictionary containing allowed scope variables.
        parameters (dict): A dictionary of parameters to substitute into the query.

    Returns:
        str: The result of the query execution, or None if an error occurred.
    """

    try:
        # Validate query template
        if not isinstance(query_template, str):
            raise TypeError("query_template must be a string")
        if not re.match(r"^[a-zA-Z0-9_]+$", query_template):
            raise ValueError("query_template contains invalid characters")

        # Validate scope
        if not isinstance(scope, dict):
            raise TypeError("scope must be a dictionary")
        for key in scope:
            if not isinstance(key, str):
                raise TypeError("Scope keys must be strings")

        # Validate parameters
        if not isinstance(parameters, dict):
            raise TypeError("parameters must be a dictionary")
        for key, value in parameters.items():
            if not isinstance(key, str):
                raise TypeError("Parameter keys must be strings")
            if not isinstance(value, (str, int, float, bool)):
                raise TypeError("Parameter values must be strings, integers, floats, or booleans")

        # Sanitize parameters
        sanitized_params = {}
        for key, value in parameters.items():
            if key in scope:
                sanitized_params[key] = str(value)  # Convert to string for safe substitution
            else:
                logging.warning(f"Parameter '{key}' is not in the allowed scope and will be ignored.")

        # Construct the query using safe string formatting
        query = query_template.format(**sanitized_params)

        # Execute the query using subprocess with shell=False
        logging.info(f"Executing query: {query}")
        result = subprocess.run(query, shell=False, capture_output=True, text=True).stdout

        return result

    except (TypeError, ValueError, Exception) as e:
        logging.error(f"Error executing query: {e}")
        return None

import subprocess
import time
import re
import os
import logging
from datetime import datetime
import shlex

def secure_adb_command(command):
    """
    Sanitizes and validates the adb command to prevent command injection.
    """
    if not isinstance(command, list):
        raise TypeError("Command must be a list.")

    allowed_commands = ["adb"]
    allowed_args = {
        "adb": ["devices", "wait-for-device", "shell"]
    }

    sanitized_command = []
    for part in command:
        if part in allowed_commands or (command[0] == "adb" and part in allowed_args.get("adb", [])):
            sanitized_command.append(part)
        else:
            logging.warning(f"Blocked potentially unsafe command part: {part}")
            raise ValueError(f"Invalid command or argument: {part}")

    return sanitized_command

def capture_screenshot(output_dir, filename):
    """
    Captures a screenshot using adb and saves it to the specified directory.
    """
    try:
        command = ["adb", "shell", "screencap", "-p"]
        output_path = os.path.join(output_dir, filename)
        if not all(os.path.normpath(p) == p for p in output_path.split(os.sep)):
            raise ValueError("Invalid output path: Directory traversal detected.")
        command.append(output_path)
        subprocess.run(command, check=True, capture_output=True)
        logging.info(f"Screenshot saved to {output_path}")
    except subprocess.CalledProcessError as e:
        logging.error(f"Error capturing screenshot: {e.stderr.decode()}")
    except ValueError as e:
        logging.error(f"Invalid adb command: {e}")
    except Exception as e:
        logging.error(f"Unexpected error capturing screenshot: {e}")

def parse_logcat(logcat_output, log_file):
    """
    Parses logcat output and saves relevant information to a file.
    """
    try:
        with open(log_file, "a") as f:
            for line in logcat_output.splitlines():
                match = re.match(r"(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}.\d{3}) (.*)", line)
                if match:
                    timestamp = match.group(1)
                    message = match.group(2)
                    f.write(f"{timestamp}: {message}
")
        logging.info(f"Logcat data saved to {log_file}")
    except IOError as e:
        logging.error(f"Error writing to log file: {e}")
    except Exception as e:
        logging.error(f"Unexpected error parsing logcat: {e}")

def main(output_dir, screenshot_interval, log_file):
    """
    Main function to capture screenshots and parse logcat data.
    """
    logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

    if not os.path.exists(output_dir):
        try:
            os.makedirs(output_dir)
        except OSError as e:
            logging.error(f"Error creating output directory: {e}")
            return

    try:
        # Check if device is connected
        result = subprocess.run(secure_adb_command(["adb", "devices"]), capture_output=True, text=True, check=True)
        if "device" not in result.stdout:
            logging.error("No device connected.")
            return

        if not isinstance(screenshot_interval, int) or screenshot_interval <= 0:
            logging.error("Invalid screenshot interval. Must be a positive integer.")
            return

        while True:
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            screenshot_filename = f"screenshot_{timestamp}.png"
            capture_screenshot(output_dir, screenshot_filename)

            # Capture logcat output
            try:
                command = ["adb", "shell", "logcat", "-v", "time", "-d"]
                result = subprocess.run(command, capture_output=True, text=True, check=True)
                logcat_output = result.stdout
                parse_logcat(logcat_output, log_file)
            except subprocess.CalledProcessError as e:
                logging.error(f"Error capturing or parsing logcat: {e.stderr.decode()}")
            except ValueError as e:
                logging.error(f"Invalid adb command: {e}")
            except Exception as e:
                logging.error(f"Unexpected error capturing or parsing logcat: {e}")

            time.sleep(screenshot_interval)

    except KeyboardInterrupt:
        logging.info("Program interrupted by user.")
    except subprocess.CalledProcessError as e:
        logging.error(f"ADB command failed: {e.stderr.decode()}")
    except Exception as e:
        logging.error(f"An unexpected error occurred: {e}")

if __name__ == "__main__":
    output_directory = "screenshots"
    screenshot_interval_seconds = 60
    log_file_path = "logcat_data.txt"

    main(output_directory, screenshot_interval_seconds, log_file_path)

