import requests
import re
import os
import urllib.parse

def send_message_to_ai(text_input, context=None, max_retries=3):
    """
    Sends a message to a conversation AI workspace and receives a response.
    Handles exceptions and retries until a valid response is received.

    Args:
        text_input (str): The text input to send to the AI.
        context (str, optional): The context for the conversation. Defaults to None.
        max_retries (int, optional): The maximum number of retries. Defaults to 3.

    Returns:
        str: The AI's response, or None if the maximum number of retries is reached.
    """

    if not isinstance(text_input, str):
        raise TypeError("text_input must be a string")
    text_input = re.sub(r'[^\w\s\-.,?!;:]', '', text_input)
    if not text_input:
        return "Input is empty after sanitization."

    if not isinstance(context, str):
        raise TypeError("context must be a string")
    context = re.sub(r'[^\w\s\-.,?!;:]', '', context)

    api_url = os.environ.get("AI_WORKSPACE_URL")
    if not api_url:
        raise ValueError("AI_WORKSPACE_URL environment variable not set")

    try:
        result = urllib.parse.urlparse(api_url)
        if not all([result.scheme, result.netloc]):
            raise ValueError("Invalid AI_WORKSPACE_URL format")
    except:
        raise ValueError("Invalid AI_WORKSPACE_URL format")

    headers = {"Content-Type": "application/json"}

    for attempt in range(max_retries):
        try:
            payload = {"text": text_input, "context": context}
            response = requests.post(api_url, json=payload, headers=headers, timeout=10)
            response.raise_for_status()

            response_json = response.json()
            if "response" in response_json:
                return response_json["response"]
            else:
                print(f"Unexpected response format: {response_json}")
                return None

        except requests.exceptions.ConnectionError as e:
            print(f"Connection error (attempt {attempt + 1}/{max_retries}): {e}")
            if attempt < max_retries - 1:
                print("Retrying...")
            else:
                print("Max retries reached.")
                return None
        except requests.exceptions.Timeout as e:
            print(f"Timeout error (attempt {attempt + 1}/{max_retries}): {e}")
            if attempt < max_retries - 1:
                print("Retrying...")
            else:
                print("Max retries reached.")
                return None
        except requests.exceptions.RequestException as e:
            print(f"Request failed (attempt {attempt + 1}/{max_retries}): {e}")
            if attempt < max_retries - 1:
                print("Retrying...")
            else:
                print("Max retries reached.")
                return None
        except ValueError as e:
            print(f"JSON decoding error: {e}")
            return None
        except Exception as e:
            print(f"An unexpected error occurred: {e}")
            return None

    return None  # Return None if max retries are reached

