import configparser
import os

def read_settings_file(file_path, default_settings):
    """
    Reads a settings file and returns a dictionary containing its key-value pairs.
    If a key is not found in the file, it should return a default value.
    Handles cases where the file does not exist or cannot be read.

    Args:
        file_path (str): The path to the settings file.
        default_settings (dict): A dictionary containing default settings.

    Returns:
        dict: A dictionary containing the settings from the file, or the default settings if the file is not found or cannot be read.
    """
    config = configparser.ConfigParser()
    try:
        if not os.path.exists(file_path):
            return default_settings

        config.read(file_path)

        settings = {}
        for key, default_value in default_settings.items():
            try:
                settings[key] = config.get('DEFAULT', key, fallback=default_value)
            except configparser.NoOptionError:
                settings[key] = default_value
            except Exception as e:
                print(f"Error reading setting {key}: {e}")
                settings[key] = default_value

        return settings

    except FileNotFoundError:
        return default_settings
    except IOError as e:
        print(f"IOError reading settings file: {e}")
        return default_settings
    except Exception as e:
        print(f"Unexpected error reading settings file: {e}")
        return default_settings

