            raise ValueError("directory_path is not a valid directory")
        if not os.path.isfile(statistic_file_path):
            raise ValueError("statistic_file_path is not a valid file")

        directory_path = os.path.abspath(directory_path)
        if not directory_path.startswith(os.path.abspath(os.getcwd())):
            raise ValueError("directory_path is not within the current working directory")

        try:
            with open(statistic_file_path, 'r') as f:
                statistic_lines = f.readlines()
        except IOError as e:
            logging.error(f"Error reading statistic file: {e}")
            raise IOError("Error reading statistic file")

        reticulations = None
        taxa = None
        increase = None
        decrease = None
        outgroup = None

        for line in statistic_lines:
            line = line.strip()
            if line.startswith('Reticulations:'):
                try:
                    reticulations = int(line.split(':')[1].strip())
                except ValueError:
                    reticulations = None
            elif line.startswith('Taxa:'):
                try:
                    taxa = int(line.split(':')[1].strip())
                except ValueError:
                    taxa = None
            elif line.startswith('Increase:'):
                try:
                    increase = float(line.split(':')[1].strip())
                except ValueError:
                    increase = None
            elif line.startswith('Decrease:'):
                try:
                    decrease = float(line.split(':')[1].strip())
                except ValueError:
                    decrease = None
            elif line.startswith('Outgroup:'):
                outgroup = line.split(':')[1].strip()
                outgroup = re.sub(r'[^\w\s]', '', outgroup)

        if reticulations is None or taxa is None or increase is None or decrease is None or outgroup is None:
            raise ValueError("Statistic file is missing required data.")

        resized_increase = increase * coefficient
        resized_decrease = decrease * coefficient

        concatenated_alignment = ""
        alignment_files = glob.glob(os.path.join(directory_path, "*.aln"))
        max_files = 100  # Limit the number of files processed
        for i, file_path in enumerate(alignment_files):
            if i >= max_files:
                logging.warning(f"Reached maximum file limit ({max_files}). Skipping further files.")
                break
            try:
                with open(file_path, 'r') as f:
                    concatenated_alignment += f.read() + "
"
            except IOError as e:
                logging.error(f"Error reading alignment file: {e}")
