import hashlib
import copy

class SecureHash:
    def __init__(self, algorithm="sha256"):
        self.algorithm = algorithm.lower()
        self.hash_object = None
        self.hex_digest = None

        if self.algorithm not in hashlib.algorithms_available:
            raise ValueError(f"Algorithm '{algorithm}' not supported. Available algorithms: {hashlib.algorithms_available}")

        try:
            self.hash_object = hashlib.new(self.algorithm)
        except ValueError as e:
            raise ValueError(f"Error initializing hash object: {e}")

    def update(self, data):
        if not isinstance(data, str):
            raise TypeError("Input data must be a string.")
        if len(data) > 1024 * 1024:
            raise ValueError("Input data too large.")
        try:
            self.hash_object.update(data.encode('utf-8'))
        except UnicodeEncodeError:
            self.hash_object.update(data.encode('utf-8', 'replace'))
        except Exception as e:
            raise RuntimeError(f"Error updating hash object: {e}")

    def digest(self):
        if self.hash_object is None:
            raise ValueError("Hash object not initialized. Call update() first.")
        try:
            self.hex_digest = self.hash_object.hexdigest()
            return self.hex_digest
        except Exception as e:
            raise RuntimeError(f"Error generating digest: {e}")

    def clone(self):
        """
        Creates a clone of the hash object, allowing for efficient
        computation of digests for strings that share a common initial substring.
        """
        cloned_hash = SecureHash(self.algorithm)
        if self.hash_object:
            cloned_hash.hash_object = hashlib.new(self.algorithm)
            cloned_hash.hash_object.update(self.hash_object.digest())
        return cloned_hash

    def get_algorithm(self):
        return self.algorithm

    def reset(self):
        """Resets the hash object to its initial state."""
        self.hash_object = hashlib.new(self.algorithm)
        self.hex_digest = None

def calculate_hash(input_string, algorithm="sha256"):
    """
    Calculates the cryptographic hash of a string using the specified algorithm.

    Args:
        input_string (str): The string to hash.
        algorithm (str, optional): The hash algorithm to use (e.g., "md5", "sha256").
                                    Defaults to "sha256".

    Returns:
        str: The hexadecimal representation of the hash value.

    Raises:
        TypeError: If input_string is not a string.
        ValueError: If the algorithm is not supported.
    """
    if not isinstance(input_string, str):
        raise TypeError("Input must be a string.")

    try:
        secure_hash = SecureHash(algorithm)
        secure_hash.update(input_string)
        return secure_hash.digest()
    except (TypeError, ValueError, RuntimeError) as e:
        raise  # Re-raise the exception to be handled by the caller

