import time
import platform
import subprocess
import psutil

def terminate_process(pid, initial_sleep=1, max_sleep=60, sleep_factor=2):
    """
    Terminates a process gracefully by sending a signal (SIGTERM) or using taskkill (Windows).

    Args:
        pid (int): The process ID to terminate.
        initial_sleep (int): The initial sleep time in seconds.
        max_sleep (int): The maximum sleep time in seconds.
        sleep_factor (float): The factor to increase the sleep time by.

    Returns:
        int: 0 if the process was terminated successfully, -1 if the process was not found or an error occurred.
    """

    if not isinstance(pid, int):
        return -1

    if pid <= 0:
        return -1

    failed = False
    sleep_time = initial_sleep

    try:
        while not failed:
            try:
                if platform.system() == 'Windows':
                    # Use taskkill on Windows
                    try:
                        subprocess.run(['taskkill', '/F', '/PID', str(pid)])
                    except subprocess.CalledProcessError as e:
                        if e.returncode == 1223:
                            failed = True
                            return -1
                        else:
                            print(f"Error terminating process on Windows: {e}")
                            failed = True
                            return -1
                else:
                    # Use signal.SIGTERM on Unix-like systems
                    try:
                        os.kill(pid, signal.SIGTERM)
                    except OSError as e:
                        if e.errno == 3:  # Process not found
                            failed = True
                            return -1
                        else:
                            print(f"Error terminating process: {e}")
                            failed = True
                            return -1

                # Check if the process is still running (platform-dependent)
                if platform.system() == 'Windows':
                    if psutil.pid_exists(pid):
                        try:
                            subprocess.run(['tasklist', '/FI', f"PID eq {pid}"])
                        except subprocess.CalledProcessError:
                            pass
                        else:
                            time.sleep(sleep_time)
                            sleep_time = min(sleep_time * sleep_factor, max_sleep)
                    else:
                        pass
                else:
                    if psutil.pid_exists(pid):
                        try:
                            subprocess.run(['ps', '-p', str(pid)])
                        except subprocess.CalledProcessError:
                            pass
                        else:
                            time.sleep(sleep_time)
                            sleep_time = min(sleep_time * sleep_factor, max_sleep)
                    else:
                        pass

            except Exception as e:
                print(f"Unexpected error during termination: {e}")
                failed = True
                return -1

            if sleep_time > max_sleep:
                failed = True
                return -1

    except Exception as e:
        print(f"An error occurred: {e}")
        return -1

    return -1

