from flask import Flask, render_template, request, redirect, url_for
from werkzeug.security import bcrypt
import uuid

app = Flask(__name__)
app.secret_key = os.urandom(24)
app.template_folder = 'templates'

class BaseView:
    def __init__(self, template_path, login_url):
        self.template_path = template_path
        self.login_url = login_url

    def render_template(self, data):
        try:
            return render_template(self.template_path, **data)
        except Exception as e:
            print(f"Error rendering template: {e}")
            return "Error rendering template."

class LoginView(BaseView):
    def __init__(self, login_url):
        super().__init__("login.html", login_url)

    def get(self):
        try:
            uid = request.args.get('uid')
            token = request.args.get('token')

            if not uid or not token:
                return self.render_template({"error": "Missing UID or token."})

            # Validate UID (UUID)
            try:
                uid = uuid.UUID(uid)
            except ValueError:
                return self.render_template({"error": "Invalid UID."})

            # Validate token (HMAC-SHA256)
            secret_key = app.secret_key
            message = str(uid).encode('utf-8')
            expected_token = hmac.new(secret_key, message, hashlib.sha256).hexdigest()

