def validate_api_key(api_key):
    """Validates the API key format."""
    if not isinstance(api_key, str):
        return False
    if not re.match(r"^[a-zA-Z0-9_-]+$", api_key):
        return False
    return True

def validate_api_secret(api_secret):
    """Validates the API secret format."""
    if not isinstance(api_secret, str):
        return False
    # API secrets can be more complex, adjust regex as needed
    if not re.match(r"^[a-zA-Z0-9_-]+$", api_secret):
        return False
    return True

def generate_authorization_url(api_key, api_secret, redirect_uri):
    """Generates the OAuth2 authorization URL."""

    if not validate_api_key(api_key):
        raise ValueError("Invalid API Key format.")
    if not validate_api_secret(api_secret):
        raise ValueError("Invalid API Secret format.")

    # Sanitize redirect URI
    try:
        redirect_uri = urllib.parse.urlparse(redirect_uri).geturl()
    except Exception:
        raise ValueError("Invalid Redirect URI format.")

    if redirect_uri not in ALLOWED_REDIRECT_URIS:
        raise ValueError("Invalid Redirect URI. Not in allowed list.")

    query_params = {
        'client_id': api_key,
        'redirect_uri': redirect_uri,
        'response_type': 'code',
        'scope': 'read write'
    }
    authorization_url = f"https://example.com/oauth/authorize?{urllib.parse.urlencode(query_params)}"
    return authorization_url

