import os
import hashlib
import logging

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def secure_file_version_update(file_path, version_file_path, hash_algorithm='sha256'):
    try:
        if not isinstance(file_path, str) or not isinstance(version_file_path, str):
            logging.error("File paths must be strings.")
            return False
        if not os.path.exists(file_path):
            logging.error(f"File not found: {file_path}")
            return False
        if not os.path.exists(version_file_path):
            logging.warning(f"Version file not found: {version_file_path}.  Creating it.")
            try:
                with open(version_file_path, 'w') as f:
                    pass  # Create an empty file
            except Exception as e:
                logging.error(f"Error creating version file: {e}")
                return False

        with open(file_path, 'rb') as f:
            file_contents = f.read()

        hasher = hashlib.new(hash_algorithm)
        hasher.update(file_contents)
        current_hash = hasher.hexdigest()

        try:
            with open(version_file_path, 'r') as f:
                stored_hash = f.read().strip()
        except FileNotFoundError:
            stored_hash = ""
        except Exception as e:
            logging.error(f"Error reading version file: {e}")
            return False

        if current_hash != stored_hash:
            try:
                with open(version_file_path, 'w') as f:
                    f.write(current_hash)
                logging.info(f"File updated. New hash: {current_hash}")
                return True
            except Exception as e:
                logging.error(f"Error writing to version file: {e}")
                return False
        else:
            logging.info("File is already up to date.")
            return False

    except Exception as e:
        logging.error(f"An unexpected error occurred: {e}")
        return False

