def get_percentile_function(distribution_name, values, **kwargs):
    """
    Returns the percentile function (ppf) for the given distribution using the provided values.

    Args:
        distribution_name (str): The name of the distribution.
        values (list): A list of values to use for calculating the percentile function.
        **kwargs: Optional parameters to customize the calculation.

    Returns:
        function: The percentile function (ppf) for the given distribution.
                  Returns None if the distribution does not have a ppf function defined.
    """
    try:
        # Validate distribution_name
        if not isinstance(distribution_name, str):
            raise TypeError("distribution_name must be a string")
        if not distribution_name:
            raise ValueError("distribution_name cannot be empty")

        # Validate values
        if not isinstance(values, list):
            raise TypeError("values must be a list")
        if not values:
            raise ValueError("values cannot be empty")
        try:
            values = [float(v) for v in values]  # Convert to float and validate
        except ValueError:
            raise ValueError("values must contain numeric values")

        # Sanitize values (remove duplicates and sort)
        sanitized_values = sorted(list(set(values)))

        allowed_distributions = ['norm', 't', 'expon', 'uniform', 'gamma']
        if distribution_name.lower() == 'empirical':
            return emp.ppf(sanitized_values, **kwargs)
        elif distribution_name.lower() in allowed_distributions:
            dist = getattr(stats, distribution_name.lower())
            return dist.ppf
        else:
            return None
    except (TypeError, ValueError) as e:
        print(f"Error: {e}")
        return None
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
