import shelve
import re
import os
import logging

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def create_data_filter(db_path, data_types=None):
    """
    Creates a filter for recording and playback of data based on data types,
    using the shelve module for storage.

    Args:
        db_path (str): The path to the shelve database file.
        data_types (list, optional): A list of data types to filter.
                                     Defaults to None (all data types).

    Returns:
        dict: A dictionary containing the filter functions (record, playback, clear).
              Returns None if an error occurs.
    """

    if not isinstance(db_path, str):
        logging.error("db_path must be a string.")
        return None

    db_dir = os.path.dirname(db_path)
    if not os.path.exists(db_dir):
        try:
            os.makedirs(db_dir)
        except OSError as e:
            logging.error(f"Error creating directory: {e}")
            return None

    if not re.match(r"^[a-zA-Z0-9_]+$", os.path.basename(db_path)):
        logging.error("db_path contains invalid characters.")
        return None

    if data_types is not None:
        if not isinstance(data_types, list):
            logging.error("data_types must be a list.")
            return None
        for dt in data_types:
            if not isinstance(dt, str):
                logging.error("All elements in data_types must be strings.")
                return None
            if not re.match(r"^[a-zA-Z0-9_]+$", dt):
                logging.error("Invalid data type name: {}".format(dt))
                return None

    try:
        db = shelve.open(db_path)
    except Exception as e:
        logging.error("Error opening shelve database: {}".format(e))
        return None

    def record(data, data_type):
        """Records data of a specific type to the database."""
        if not isinstance(data, (int, float, str, bytes, list, tuple, dict, set)):
            logging.warning("Unsupported data type for recording: {}".format(type(data)))
            return False

        if not isinstance(data_type, str):
            logging.error("data_type must be a string.")
            return False

        if not re.match(r"^[a-zA-Z0-9_]+$", data_type):
            logging.error("Invalid data type name: {}".format(data_type))
            return False

        try:
            if data_types is None or data_type in data_types:
                db[data_type] = data
            return True
        except Exception as e:
            logging.error("Error recording data: {}".format(e))
            return False

    def playback(data_type):
        """Retrieves data of a specific type from the database."""
        if not isinstance(data_type, str):
            logging.error("data_type must be a string.")
            return None

        if not re.match(r"^[a-zA-Z0-9_]+$", data_type):
            logging.error("Invalid data type name: {}".format(data_type))
            return None

        try:
            data = db.get(data_type)
            return data
        except Exception as e:
            logging.error("Error playing back data: {}".format(e))
            return None

    def clear():
        """Clears all data from the database."""
        try:
            db.clear()
            return True
        except Exception as e:
            logging.error("Error clearing database: {}".format(e))
            return False

    try:
        db.close()
    except Exception as e:
        logging.error("Error closing shelve database: {}".format(e))
    return {"record": record, "playback": playback, "clear": clear}

