def validate_path(path: str) -> str:
    """Validates and sanitizes a file path."""
    if not isinstance(path, str):
        raise TypeError("Path must be a string.")
    if not re.match(r"^[a-zA-Z0-9_\-\.]+$", path):
        raise ValueError("Invalid characters in path.")
    if os.path.isabs(path):
        if not os.path.exists(path):
            raise FileNotFoundError(f"Path does not exist: {path}")
    else:
        abs_path = os.path.abspath(path)
        if not os.path.exists(abs_path):
            raise FileNotFoundError(f"Relative path does not exist: {path}")
    return os.path.normpath(path)

def configure_vnx_cli(naviseccli_path: Optional[str] = None, username: Optional[str] = None, password: Optional[str] = None, interval: Optional[int] = None):
    """
    Configures parameters for the EMC VNX CLI driver.

    Args:
        naviseccli_path: Path to the naviseccli binary.
        username: Username for authentication.
        password: Password for authentication.
        interval: Interval in seconds for various tasks.
    """
