class ConfigurationManager:
    def __init__(self, config_file=None):
        self.config = {}
        self.config_file = config_file
        self.logger = logging.getLogger(__name__)
        self.handlers = []
        self.config_dir = "config"  # Define a base directory for configuration files

    def register_handler(self, handler):
        if handler not in self.handlers:
            self.handlers.append(handler)

    def broadcast(self, key, value):
        for handler in self.handlers:
            try:
                handler(key, value)
            except Exception as e:
                self.logger.error(f"Error broadcasting {key}: {e}")

    def load_config(self):
        if self.config_file:
            try:
                abs_path = os.path.abspath(self.config_file)
                norm_path = os.path.normpath(abs_path)

                if not norm_path.startswith(os.path.abspath(self.config_dir)):
                    raise ValueError("Invalid configuration file path: Path is outside the allowed directory.")

                with open(norm_path, 'r') as f:
                    config_data = json.load(f)
                    self.config.update(config_data)
            except FileNotFoundError:
                self.logger.warning(f"Configuration file not found: {self.config_file}")
            except json.JSONDecodeError:
                self.logger.error(f"Invalid JSON in configuration file: {self.config_file}")
            except ValueError as e:
                self.logger.error(f"Error loading configuration: {e}")

        parser = argparse.ArgumentParser(description='Process command-line arguments for configuration.')
        parser.add_argument('--config', type=str, help='Path to configuration file (overrides default)')
        args = parser.parse_args()

        if args.config:
            self.config_file = args.config
