class QuandlSpider(scrapy.Spider):
    name = "quandl_spider"
    allowed_domains = ["example.com"]
    start_urls = ["https://www.example.com/data"]

    custom_setting = "MY_SETTING"

    def __init__(self, quandl_api_key=None, dataset_code=None, *args, **kwargs):
        super(QuandlSpider, self).__init__(*args, **kwargs)
        self.quandl_api_key = quandl_api_key
        self.dataset_code = dataset_code

        if self.quandl_api_key:
            self.set_quandl_api_key(self.quandl_api_key)
        else:
            # Use environment variable if API key is not provided
            self.quandl_api_key = os.environ.get("QUANDL_API_KEY")
            if self.quandl_api_key:
                self.set_quandl_api_key(self.quandl_api_key)
            else:
                raise ValueError("Quandl API key not provided and not found in environment variable.")

        self.dataset_code = self.dataset_code if self.dataset_code else "EXAMPLE/DATA"

    def set_quandl_api_key(self, api_key):
        if not isinstance(api_key, str):
            raise TypeError("Quandl API key must be a string.")
        if not re.match(r"^[a-zA-Z0-9_-]+$", api_key):
            raise ValueError("Quandl API key contains invalid characters.")
        quandl.ApiConfig.api_key = api_key

    def parse(self, response):
        # Validate and sanitize the response URL
        try:
            result = urlparse(response.url)
            if not all([result.scheme, result.netloc]):
                raise ValueError("Invalid URL")
        except Exception as e:
            self.logger.error(f"Invalid URL: {response.url} - {e}")
            return

        # Example: Extract data from the page
        title = response.xpath('//title/text()').get()
        if title:
            title = html.unescape(title)

        # Validate title length and characters
        if not (0 < len(title) < 255):
            self.logger.warning(f"Title length is invalid: {title}")
            title = ""

        # Example: Follow links within the allowed domain
        for href in response.xpath('//a/@href').getall():
            absolute_url = urljoin(response.url, href)
            try:
                result = urlparse(absolute_url)
                if result.netloc == self.allowed_domains[0]:
                    yield scrapy.Request(absolute_url, callback=self.parse)
            except Exception as e:
                self.logger.error(f"Invalid URL: {absolute_url} - {e}")

        # Example: Send data to Quandl
        data = {
            'title': title,
            # Add more data fields as needed
        }

        try:
            if title:
                quandl.put(self.dataset_code, data)
                self.logger.info(f"Data sent to Quandl dataset: {self.dataset_code}")
        except quandl.errors.QuandlError as e:
            self.logger.error(f"Quandl API error: {e}")
        except Exception as e:
            self.logger.error(f"Error sending data to Quandl: {e}")

def run_spider(quandl_api_key, dataset_code, start_urls):
