import ast
import logging
import json

def evaluate_lock_definition(lock_definition_string, allowed_functions):
    """
    Parses and evaluates a lock definition string.

    Args:
        lock_definition_string (str): A string representation of the lock definition.
        allowed_functions (list): A list of tuples, where each tuple contains a function name,
                                   a list of arguments, and a dictionary of keyword arguments.

    Returns:
        tuple: A tuple containing the evaluated lock definition and a list of warnings.

    Raises:
        TypeError: If lock_definition_string is not a string or allowed_functions is not a list.
        ValueError: If lock_definition_string is empty or contains invalid syntax.
        SecurityException: If the lock definition contains disallowed functions or unsafe operations.
    """

    if not isinstance(lock_definition_string, str):
        raise TypeError("lock_definition_string must be a string.")
    if not isinstance(allowed_functions, list):
        raise TypeError("allowed_functions must be a list.")

    if not lock_definition_string:
        raise ValueError("lock_definition_string cannot be empty.")

    try:
        tree = ast.parse(lock_definition_string)

        for node in ast.walk(tree):
            if isinstance(node, ast.Name) and node.id not in [func[0] for func in allowed_functions]:
                raise SecurityException(f"Disallowed function '{node.id}' found in lock definition.")
            elif isinstance(node, ast.Call):
                function_name = node.func.id if isinstance(node.func, ast.Name) else None
                if function_name and function_name not in [func[0] for func in allowed_functions]:
                    raise SecurityException(f"Disallowed function '{function_name}' found in lock definition.")

        sanitized_lock_definition_string = lock_definition_string.strip()

        safe_globals = {}
        safe_locals = {}

        try:
            evaluated_lock_definition = json.loads(sanitized_lock_definition_string)
        except (ValueError, json.JSONDecodeError) as e:
            try:
                evaluated_lock_definition = ast.literal_eval(sanitized_lock_definition_string, safe_globals)
            except (ValueError, SyntaxError) as e:
                raise ValueError(f"Invalid lock definition: {e}")

        return evaluated_lock_definition, []

    except SyntaxError as e:
        raise ValueError(f"Invalid syntax in lock definition: {e}")
    except SecurityException as e:
        raise e
    except TypeError as e:
        raise e
    except ValueError as e:
        raise e
    except KeyError as e:
        raise e
    except Exception as e:
        logging.error(f"An unexpected error occurred during lock definition evaluation: {e}")
        raise SecurityException(f"An unexpected error occurred: {e}")

