import subprocess
import re

def get_volume_level(adjustment_command):
    """
    Retrieves the current volume level and adjusts it based on the given command.

    Args:
        adjustment_command (str): The volume adjustment command ('up', 'down', or None).

    Returns:
        str: The current volume level as a string, or an error message if the command is invalid or fails.
    """

    # Input validation and sanitization
    if not isinstance(adjustment_command, str):
        return "Error: Invalid input type.  Must be a string."

    adjustment_command = adjustment_command.strip().lower()
    if adjustment_command not in ('up', 'down', None):
        return "Error: Invalid adjustment command.  Must be 'up', 'down', or None."

    try:
        # Retrieve current volume level
        try:
            result = subprocess.run(['amixer', 'get', 'Master'], capture_output=True, text=True, check=True)
            output = result.stdout
        except FileNotFoundError:
            return "Error: amixer not found.  Please ensure it is installed."
        except subprocess.CalledProcessError as e:
            return f"Error: Failed to retrieve volume level: {e}"

        match = re.search(r'Simple mixer control: Master\s*([0-9]+)%', output)
        if match:
            try:
                current_volume = int(match.group(1))
            except ValueError:
                return "Error: Could not parse volume level from amixer output."
        else:
            return "Error: Could not parse volume level from amixer output."

        # Adjust volume if command is provided
        if adjustment_command == 'up':
            new_volume = min(100, current_volume + 10)
            try:
                subprocess.run(['amixer', 'set', 'Master', f'{new_volume}%'], check=True)
            except subprocess.CalledProcessError as e:
                return f"Error: Failed to increase volume: {e}"
        elif adjustment_command == 'down':
            new_volume = max(0, current_volume - 10)
            try:
                subprocess.run(['amixer', 'set', 'Master', f'{new_volume}%'], check=True)
            except subprocess.CalledProcessError as e:
                return f"Error: Failed to decrease volume: {e}"

        return str(current_volume) + "%"

    except Exception as e:
        return f"Error: An unexpected error occurred: {e}"

