import os
import json
import logging
from typing import List, Dict
from osgi import BundleContext, Bundle

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def find_images_in_bundle(bundle_name: str, image_types: List[str], context: BundleContext) -> List[str]:
    """
    Searches for images in a bundle, given the bundle's symbolic name and a list of image types.

    Args:
        bundle_name: The symbolic name of the bundle.
        image_types: A list of image types to search for (e.g., ["jpg", "png"]).
        context: The BundleContext to use for finding the bundle.

    Returns:
        A list of images found in the bundle.
    """

    cache_file = "bundle_image_types.json"
    bundle_image_types: Dict[str, List[str]] = {}

    # Validate inputs
    if not isinstance(bundle_name, str):
        raise TypeError("bundle_name must be a string")
    if not isinstance(image_types, list):
        raise TypeError("image_types must be a list")
    for image_type in image_types:
        if not isinstance(image_type, str):
            raise TypeError("image_types must contain only strings")

    try:
        with open(cache_file, "r") as f:
            bundle_image_types = json.load(f)
    except FileNotFoundError:
        # Create a new dictionary with all possible image types if the cache file doesn't exist
        all_image_types = ["jpg", "jpeg", "png", "gif", "bmp", "webp", "svg"]
        for name in all_image_types:
            bundle_image_types[name] = True
        with open(cache_file, "w") as f:
            json.dump(bundle_image_types, f, indent=4)
    except json.JSONDecodeError:
        # Handle invalid JSON in the cache file - reset to default
        all_image_types = ["jpg", "jpeg", "png", "gif", "bmp", "webp", "svg"]
        for name in all_image_types:
            bundle_image_types[name] = True
        with open(cache_file, "w") as f:
            json.dump(bundle_image_types, f, indent=4)
    except Exception as e:
        logging.error(f"Error reading/writing cache file: {e}")
        return []

    bundle: Bundle = None
    try:
        bundle = context.get_bundle(bundle_name)
        if bundle is None:
            logging.warning(f"Bundle '{bundle_name}' not found.")
            return []
    except Exception as e:
        logging.error(f"Error getting bundle: {e}")
        return []

    if bundle is None:
        return []

    root_path = bundle.get_entry("/").path
    if not root_path:
        logging.warning(f"Bundle '{bundle_name}' has no root entry.")
        return []

    images: List[str] = []
    try:
        for root, _, files in os.walk(root_path, maxdepth=10):
            for file in files:
                file_extension = file.split(".")[-1].lower()
                if file_extension in image_types:
                    images.append(os.path.join(root, file))
    except Exception as e:
        logging.error(f"Error walking bundle directory: {e}")
        return []

    return images

