import hashlib
import os
import secrets
import re

class UserAccount:
    def __init__(self, username, phone_number, emergency_contact):
        self.username = username
        self.password_hash = None
        self.salt = None
        self.phone_number = self._sanitize_phone_number(phone_number)
        self.emergency_contact = self._sanitize_emergency_contact(emergency_contact)
        self.secret_key = None

    def _sanitize_phone_number(self, phone_number):
        if not isinstance(phone_number, str):
            raise TypeError("Phone number must be a string.")
        phone_number = re.sub(r'\D', '', phone_number)  # Remove non-digits
        if not phone_number:
            raise ValueError("Phone number cannot be empty.")
        if len(phone_number) < 7 or len(phone_number) > 15:
            raise ValueError("Phone number must be between 7 and 15 digits.")
        return phone_number

    def _sanitize_emergency_contact(self, emergency_contact):
        if not isinstance(emergency_contact, str):
            raise TypeError("Emergency contact must be a string.")
        emergency_contact = re.sub(r'\D', '', emergency_contact)
        if not emergency_contact:
            raise ValueError("Emergency contact cannot be empty.")
        if len(emergency_contact) < 7 or len(emergency_contact) > 15:
            raise ValueError("Emergency contact must be between 7 and 15 digits.")
        return emergency_contact

    def set_password(self, password):
        if not isinstance(password, str):
            raise TypeError("Password must be a string.")
        if len(password) < 16:
            raise ValueError("Password must be at least 16 characters long.")

        try:
            salt = secrets.token_hex(16)
            salted_password = salt + password
            hashed_password = hashlib.pbkdf2_hmac('sha256', salted_password.encode('utf-8'), salt.encode('utf-8'), 100000)
            self.password_hash = hashed_password.hex()
            self.salt = salt
        except ValueError as e:
            print(f"Error generating password hash: {e}")
            raise

    def verify_password(self, password):
        if not isinstance(password, str):
            raise TypeError("Password must be a string.")

        if self.password_hash is None or self.salt is None:
            return False

        try:
            salted_password = self.salt + password
            hashed_password = hashlib.pbkdf2_hmac('sha256', salted_password.encode('utf-8'), self.salt.encode('utf-8'), 100000)
            return hashed_password.hex() == self.password_hash
        except ValueError as e:
            print(f"Error verifying password: {e}")
            return False

    def generate_secret_key(self, key_length=32):
        if self.secret_key is not None:
