import os

def secure_replace_text_in_file(filename, old_text, new_text):
    try:
        if not isinstance(filename, str):
            raise TypeError("Filename must be a string.")
        if not isinstance(old_text, str):
            raise TypeError("Old text must be a string.")
        if not isinstance(new_text, str):
            raise TypeError("New text must be a string.")

        if not os.path.exists(filename):
            raise FileNotFoundError(f"File not found: {filename}")

        if not os.access(filename, os.R_OK):
            raise PermissionError(f"No read access to file: {filename}")

        if not os.access(filename, os.W_OK):
            raise PermissionError(f"No write access to file: {filename}")

        # Read the file contents safely
        with open(filename, 'r', encoding='utf-8') as f:
            file_contents = f.read()

        # Perform the replacement
        modified_contents = file_contents.replace(old_text, new_text)

        # Write the modified contents back to the file
        with open(filename, 'w', encoding='utf-8') as f:
            f.write(modified_contents)

        return True

    except (TypeError, FileNotFoundError, PermissionError, OSError) as e:
        print(f"Error processing file: {e}")
        return False
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return False

