import ut

def register_and_execute_doctest(module_name, function_name, *args, **kwargs):
    """
    Registers and executes doctest experiments for a given module and function.

    Args:
        module_name (str): The name of the module.
        function_name (str): The name of the function.
        *args: Positional arguments to pass to the function.
        **kwargs: Keyword arguments to pass to the function.

    Returns:
        The result of the executed function.
    """
    allowed_modules = ["ut"]
    allowed_functions = ["register_doctest"]

    if not isinstance(module_name, str):
        raise TypeError("module_name must be a string.")
    if not isinstance(function_name, str):
        raise TypeError("function_name must be a string.")

    if module_name not in allowed_modules:
        raise ValueError(f"Module '{module_name}' is not allowed.")
    if function_name not in allowed_functions and module_name == "ut":
        raise ValueError(f"Function '{function_name}' is not allowed in module '{module_name}'.")

    try:
        module = importlib.import_module(module_name)
    except ImportError:
        raise ValueError(f"Module '{module_name}' not found.")
    except Exception as e:
        raise ValueError(f"Error importing module '{module_name}': {e}")

    try:
        function = getattr(module, function_name)
    except AttributeError:
        raise ValueError(f"Function '{function_name}' not found in module '{module_name}'.")
    except Exception as e:
        raise ValueError(f"Error retrieving function '{function_name}' from module '{module_name}': {e}")

    try:
        result = function(*args, **kwargs)
        ut.register_doctest(module_name, function_name, args=args, kwargs=kwargs, result=result)
        return result
    except Exception as e:
        import logging
        logging.exception(f"Error executing function '{function_name}' in module '{module_name}'")
        raise  # Re-raise the exception to signal failure

