class SecureInputIterator:
    def __init__(self, source_type: str, source_path: str, fail_on_missing: bool = True):
        """
        Initializes the SecureInputIterator.

        Args:
            source_type (str): The type of source, either "file" or "bucket".
            source_path (str): The path to the file or bucket.
            fail_on_missing (bool): Whether to raise an exception if the source is missing.
