    def _validate_source_path(self, path: str) -> str:
        """
        Validates and sanitizes the source path.

        Args:
            path (str): The source path to validate.

        Returns:
            str: The validated source path.

        Raises:
            ValueError: If the path is invalid.
        """
        if not isinstance(path, str):
            raise TypeError("Source path must be a string.")
        if not path:
            raise ValueError("Source path cannot be empty.")
        abs_path = os.path.abspath(os.path.normpath(path))
        if not abs_path.startswith(os.path.abspath(".")):
            raise ValueError("Path is outside the allowed directory.")
        return abs_path

    def __iter__(self) -> Iterator[str]:
        """
        Returns an iterator over the contents of the file or bucket.
        """
        try:
            if self.source_type == "file":
                try:
                    self.file_handle = open(self.source_path, 'r', encoding='utf-8')
                    self.iterator = self.file_handle.readlines()
