import logging
import os

def execute_command(command_string, env=None):
    try:
        if not command_string:
            return 1

        allowed_commands = ["ls", "grep", "cat", "echo"]
        command_tokens = command_string.split()

        if not command_tokens:
            return 1

        if command_tokens[0] not in allowed_commands:
            logging.error(f"Command not allowed: {command_string}")
            return 1

        if env is None:
            env = os.environ.copy()

        sanitized_env = {}
        allowed_env_vars = ["PATH", "LD_LIBRARY_PATH", "HOME", "USER", "LOGNAME", "TERM", "PS1"]
        for key, value in env.items():
            if key in allowed_env_vars:
                sanitized_env[key] = value

        command_list = [command_tokens[0]]
        for token in command_tokens[1:]:
            if token:
                command_list.append(token)

        if len(command_list) > 10:
            logging.warning("Command is excessively long.")
            return 1

        # Log the command and environment variables
        logging.debug(f"Executing command: {command_string}")
        if env:
            logging.debug(f"Environment variables: {env}")

        process = subprocess.run(
            command_list,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env=sanitized_env,
            text=True,
            capture_output=True
        )

        stdout = process.stdout
        stderr = process.stderr
        return_code = process.returncode

        # Log stdout and stderr (handle potential encoding issues)
        try:
            logging.debug(f"Stdout: {stdout}")
            logging.debug(f"Stderr: {stderr}")
        except UnicodeEncodeError:
            logging.debug(f"Stdout (encoding error): {stdout.encode('utf-8', 'ignore').decode('utf-8')}")
            logging.debug(f"Stderr (encoding error): {stderr.encode('utf-8', 'ignore').decode('utf-8')}")

        return return_code

    except FileNotFoundError:
        logging.error(f"Command not found: {command_string}")
        return 127  # Standard error code for command not found
    except subprocess.CalledProcessError as e:
        logging.error(f"Command failed with error: {e}")
        return e.returncode
    except Exception as e:
        logging.exception(f"An unexpected error occurred: {e}")
        return 1  # Or a more specific error code

