logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def copy_directory(source_dir, destination_dir):
    """
    Copies a directory and its contents from one location to another using a shell command.

    Args:
        source_dir (str): The path to the source directory.
        destination_dir (str): The path to the destination directory.
    """
    try:
        if not isinstance(source_dir, str) or not isinstance(destination_dir, str):
            raise TypeError("Source and destination directories must be strings.")

        source_dir = os.path.abspath(source_dir)
        destination_dir = os.path.abspath(destination_dir)

        if not os.path.isdir(source_dir):
            raise ValueError("Source directory does not exist or is not a directory.")

        def validate_path(path):
            if not re.match(r"^[a-zA-Z0-9_\-\.\/]+$", path):
                raise ValueError("Invalid characters in path. Only alphanumeric characters, underscores, hyphens, periods, and forward slashes are allowed.")
            return path

        source_dir = validate_path(source_dir)
        destination_dir = validate_path(destination_dir)

        if not os.path.exists(os.path.dirname(destination_dir)):
            os.makedirs(os.path.dirname(destination_dir))

        command = ['rsync', '-av', '--no-perms', '--no-owner', '--no-group', source_dir, destination_dir]
        logging.info(f"Copying directory from {source_dir} to {destination_dir}...")
        result = subprocess.run(command, capture_output=True, text=True, check=True)
        logging.info("Directory copy completed successfully.")

    except TypeError as e:
        logging.error(f"Type error: {e}")
    except ValueError as e:
        logging.error(f"Value error: {e}")
    except subprocess.CalledProcessError as e:
        if e.returncode == 1:
            logging.error(f"Rsync error: Permission denied. Check source and destination directory permissions.")
        elif e.returncode == 2:
            logging.error(f"Rsync error: No such file or directory. Check source directory path.")
        elif e.returncode == 3:
            logging.error(f"Rsync error: Option not supported.")
        elif e.returncode == 4:
            logging.error(f"Rsync error: Cannot read source directory.")
        else:
            logging.error(f"Error during copy: {e.stderr}")
    except Exception as e:
        logging.error(f"An unexpected error occurred: {e}")

