import os
import importlib.util
import sys
import logging
import ast

logging.basicConfig(level=logging.ERROR)

def execute_code_from_file(file_path):
    try:
        if not isinstance(file_path, str):
            raise TypeError("file_path must be a string")

        if not os.path.isfile(file_path):
            raise FileNotFoundError(f"File not found: {file_path}")

        if not file_path.endswith(".py"):
            raise ValueError("File must be a Python file (end with .py)")

        file_path = os.path.abspath(file_path)
        if not file_path.startswith(os.path.abspath(os.getcwd())):
            raise ValueError("File path is outside the current working directory")

        module_name = os.path.splitext(os.path.basename(file_path))[0]

        spec = importlib.util.spec_from_file_location(module_name, file_path)
        if spec is None:
            raise ValueError(f"Could not create module spec for {file_path}")

        module = importlib.util.module_from_spec(spec)
        sys.modules[module_name] = module

        try:
            with open(file_path, "r") as f:
                code = f.read()
            try:
                tree = ast.parse(code)
                ast.unparse(tree)

                # Implement a strict allowlist of allowed modules/functions
                allowed_modules = ['math', 'datetime']
                allowed_functions = ['sqrt', 'datetime.now']

                for node in ast.walk(tree):
                    if isinstance(node, ast.Import):
                        for alias in node.names:
                            if alias.name not in allowed_modules:
                                raise ValueError(f"Importing module '{alias.name}' is not allowed.")
                    elif isinstance(node, ast.Call):
                        if isinstance(node.func, ast.Name):
                            if node.func.id not in allowed_functions:
                                raise ValueError(f"Calling function '{node.func.id}' is not allowed.")
                        elif isinstance(node.func, ast.Attribute):
                            if isinstance(node.func.value, ast.Name):
                                if node.func.value.id == 'datetime' and node.func.attr not in ['now']:
                                    raise ValueError(f"Calling attribute '{node.func.attr}' of module 'datetime' is not allowed.")

                module_code = compile(code, filename=file_path, mode='exec')
                exec(module_code, module.__dict__)
            except SyntaxError as e:
                logging.error(f"Syntax error in code: {e}")
                return None
            except ValueError as e:
                logging.error(f"Value error in code: {e}")
                return None
            except Exception as e:
                logging.error(f"Error processing code: {e}")
                return None
        except Exception as e:
            logging.error(f"Error reading or processing file: {e}")
            return None

        module.module_name = module_name
        module.file_path = file_path

        return module

    except (TypeError, FileNotFoundError, ValueError) as e:
        logging.error(f"Error: {e}")
        return None
    except Exception as e:
        logging.exception(f"Unexpected error: {e}")
        return None

