def create_registration_profile(username):
    if not isinstance(username, str):
        raise TypeError("Username must be a string.")
    if not username:
        raise ValueError("Username cannot be empty.")
    if len(username) > 255:
        raise ValueError("Username must be 255 characters or less.")
    if any(c in username for c in string.punctuation):
        raise ValueError("Username cannot contain special characters.")

    salt = secrets.token_hex(16)
    data = salt.encode('utf-8') + username.encode('utf-8')
