    EXECUTE format('SELECT 1 FROM pg_tables WHERE tablename = %I', table_name);
    EXCEPTION WHEN OTHERS THEN
        RAISE EXCEPTION 'Table % does not exist.', table_name;

    -- Validate that old column exists (database-specific, example for PostgreSQL)
    EXECUTE format('SELECT 1 FROM information_schema.columns WHERE table_name = %I AND column_name = %I', table_name, old_column_name);
