        -- Add the new column
        sql_statement := format('ALTER TABLE %I ADD COLUMN %I %s', table_name, new_column_name, field_definition);
        EXECUTE sql_statement;
    ELSE
        RAISE EXCEPTION 'Invalid field definition. Allowed types are: %', allowed_types;
    END IF;

EXCEPTION
    WHEN OTHERS THEN
        -- Log the error (replace with your logging mechanism)
        -- DO NOT expose sensitive information in error messages
        RAISE EXCEPTION 'An error occurred.';
END;
$$ LANGUAGE plpgsql;

