@app.route('/', methods=['GET', 'POST'])
def index():
    if request.method == 'POST':
        client_id = request.form.get('client_id')
        client_secret = request.form.get('client_secret')

        if not client_id or not client_secret:
            return render_template('index.html', error='Client ID and Secret are required.')

        # Validate and sanitize inputs
        if not isinstance(client_id, str) or not isinstance(client_secret, str):
            return render_template('index.html', error='Client ID and Secret must be strings.')

        client_id_pattern = re.compile(r"^[A-Za-z0-9._-]+$")
        client_secret_pattern = re.compile(r"^[A-Za-z0-9._-]+$")

        if not client_id_pattern.match(client_id) or not client_secret_pattern.match(client_secret):
            return render_template('index.html', error='Client ID and Secret contain invalid characters.')

        if len(client_id) < 5 or len(client_secret) < 8:
            return render_template('index.html', error='Client ID and Secret must be of sufficient length.')

        try:
            paypalrestsdk.configure(
                {
                    "mode": os.environ.get("PAYPAL_MODE", "sandbox"),
                    "client_id": client_id,
                    "client_secret": client_secret
                }
            )

            payment = Payment.create(
                {
                    "intent": "sale",
                    "amount": "10.00",
                    "currency": "USD",
                    "description": "Payment for goods/services"
                }
            )
            # Redirect to PayPal
            for link in payment['links']:
                if link['rel'] == 'approval_url':
                    return redirect(link['href'])
            return render_template('index.html', error='Could not retrieve approval URL.')

        except PayPalRestError as e:
            return render_template('index.html', error=f'PayPal API Error: {e.message}')

    return render_template('index.html')


@app.route('/payment_status')
def payment_status():
    payment_id = request.args.get('paymentId')

    if not payment_id:
        return render_template('status.html', status='Error: Payment ID missing.')

    try:
        payment = Payment.execute(payment_id)

        if payment.status == 'approved':
            return render_template('status.html', status='Payment Successful!')
        else:
            return render_template('status.html', status=f'Payment Status: {payment.status}')

    except PayPalRestError as e:
        return render_template('status.html', status=f'PayPal API Error: {e.message}')


if __name__ == '__main__':
    app.run(debug=False)

import re
import os

def authenticate_environment_variables(env_vars, auth_mechanism="os"):
    """
    Authenticates environment variables based on the specified authentication mechanism.

    Args:
        env_vars (dict): A dictionary of environment variables.
        auth_mechanism (str): The authentication mechanism to use (e.g., "os", "st").

    Returns:
        dict: A dictionary of authenticated environment variables, or None if authentication fails.
    """

    if not isinstance(env_vars, dict):
        raise TypeError("env_vars must be a dictionary")
    if not isinstance(auth_mechanism, str):
        raise TypeError("auth_mechanism must be a string")

    auth_mechanism = auth_mechanism.lower()
    if auth_mechanism not in ("os", "st"):
        raise ValueError("Invalid auth_mechanism. Supported mechanisms are 'os' and 'st'.")

    if auth_mechanism == "os":
        try:
            auth_url = os.environ.get("OS_AUTH_URL")
            username = os.environ.get("OS_USERNAME")
            password = os.environ.get("OS_PASSWORD")
            project_name = os.environ.get("OS_PROJECT_NAME")
            project_id = os.environ.get("OS_PROJECT_ID")
            region = os.environ.get("OS_REGION_NAME")
            user_id = os.environ.get("OS_USER_ID")
            auth_version = os.environ.get("OS_AUTH_VERSION", "2.0")

            if not all([auth_url, username, password]):
                return None

            if not re.match(r"^(http|https)://", auth_url):
                return None

            if not isinstance(auth_version, str):
                return None

            auth_version = float(auth_version)
            if auth_version not in (1.0, 2.0, 3.0):
                return None

            if not isinstance(project_name, str):
                return None
            if not isinstance(project_id, str):
                return None
            if not isinstance(region, str):
                return None
            if not isinstance(user_id, str):
                return None

            authenticated_env = {
                "OS_AUTH_URL": auth_url,
                "OS_USERNAME": username,
                "OS_PASSWORD": password,
                "OS_PROJECT_NAME": project_name,
                "OS_PROJECT_ID": project_id,
                "OS_REGION_NAME": region,
                "OS_USER_ID": user_id,
                "OS_AUTH_VERSION": auth_version
            }
            return authenticated_env

        except (TypeError, ValueError):
            return None

    elif auth_mechanism == "st":
        try:
            auth_token = os.environ.get("ST_AUTH")
            user = os.environ.get("ST_USER")
            key = os.environ.get("ST_KEY")

            if not all([auth_token, user, key]):
                return None

            if not isinstance(auth_token, str) or not isinstance(user, str) or not isinstance(key, str):
                return None

            authenticated_env = {
                "ST_AUTH": auth_token,
                "ST_USER": user,
                "ST_KEY": key
            }
            return authenticated_env

        except (TypeError, ValueError):
            return None
    return None

