            return False, "Invalid IP address format."
        try:
            octets = [int(octet) for octet in ip.split('.')]
            for octet in octets:
                if not (0 <= octet <= 255):
                    return False, "IP address octet out of range."
        except ValueError:
            return False, "Invalid IP address format."
        return True, None

