import configparser
import os
import re
import hashlib
import hmac
import requests
import bcrypt
import time
import rate_limiter

CONFIG_FILE = 'config.ini'
API_ENDPOINT = os.environ.get('API_ENDPOINT', 'https://api.example.com/authenticate')
API_KEY = os.environ.get('API_KEY')
SECRET_KEY = os.environ.get('SECRET_KEY')
MAX_ATTEMPTS = 5
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX = 10

def load_credentials():
    config = configparser.ConfigParser()
    if os.path.exists(CONFIG_FILE):
        config.read(CONFIG_FILE)
        try:
            username = config['credentials']['username']
            password_hash = config['credentials']['password']
            return username, password_hash
        except KeyError:
            return None, None
    else:
        return None, None

def sanitize_string(input_string):
    if not isinstance(input_string, str):
        return ''
    return re.sub(r'[^\w\s]', '', input_string).strip()

def get_user_input(prompt):
    while True:
        try:
            user_input = input(prompt).strip()
            if user_input:
                return user_input
            else:
                print("Input cannot be empty. Please try again.")
        except KeyboardInterrupt:
            print("Exiting.")
            exit(1)
        except Exception as e:
            print(f"An error occurred: {e}. Please try again.")

def write_credentials(username, password):
    config = configparser.ConfigParser()
    hashed_password = bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt())
    config['credentials'] = {'username': username, 'password': hashed_password.decode('utf-8')}
    try:
        with open(CONFIG_FILE, 'w') as configfile:
            config.write(configfile)
    except Exception as e:
        print(f"Error writing to configuration file: {e}")
        return False
    return True

def generate_signature(username, password, secret_key):
    try:
        timestamp = str(int(time.time()))
        message = API_KEY + username + timestamp
        hmac_obj = hmac.new(secret_key.encode('utf-8'), message.encode('utf-8'), hashlib.sha256)
        signature = hmac_obj.hexdigest()
        return signature
    except Exception as e:
        print(f"Error generating signature: {e}")
        return None

def authenticate_api(username, password):
    with rate_limiter.RateLimiter(MAX_ATTEMPTS, RATE_LIMIT_WINDOW):
        try:
            if not SECRET_KEY:
                print("Secret key not found in environment variables.")
                return False

            signature = generate_signature(username, password, SECRET_KEY)
            if not signature:
                return False

            payload = {
                'username': username,
                'password': password,
                'api_key': API_KEY,
                'signature': signature
            }

            response = requests.post(API_ENDPOINT, json=payload, timeout=10)
            response.raise_for_status()

            data = response.json()
            if data.get('success'):
                return True
            else:
                return False

        except requests.exceptions.RequestException as e:
            print(f"API request failed: {e}")
            return False
        except Exception as e:
            print(f"Authentication error: {e}")
            return False

def verify_password(password, hashed_password):
    try:
        return bcrypt.checkpw(password.encode('utf-8'), hashed_password.encode('utf-8'))
    except Exception as e:
        print(f"Password verification error: {e}")
        return False

def main():
    username, password_hash = load_credentials()

    if not username or not password_hash:
        print("Username and password not found in configuration file.")
        username = get_user_input("Enter username: ")
        username = sanitize_string(username)
        password = get_user_input("Enter password: ")
        password = sanitize_string(password)

        if not write_credentials(username, password):
            print("Failed to save credentials. Exiting.")
            return

    if authenticate_api(username, password_hash):
        print("Authentication successful!")
    else:
        print("Authentication failed.")

if __name__ == "__main__":
    main()

import re
import os

def extract_version_and_create_metadata(filepath, metadata_dict_name):
    """
    Reads a text file, extracts the version number from a specific line,
    and uses that version number to populate a dictionary of metadata.

    Args:
        filepath (str): The path to the text file.
        metadata_dict_name (str): The name of the metadata dictionary.

    Returns:
        dict: A dictionary containing the metadata, or None if an error occurs.
    """
    if not isinstance(filepath, str):
        raise TypeError("Filepath must be a string.")
    if not isinstance(metadata_dict_name, str):
        raise TypeError("Metadata dictionary name must be a string.")

    if not os.path.exists(filepath):
        raise FileNotFoundError(f"File not found: {filepath}")

    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            for line in f:
                match = re.search(r"version=(\d+\.\d+\.\d+)", line)
                if match:
                    version = match.group(1)
                    break
            else:
                return None

        metadata_dict = {
            metadata_dict_name: version
        }
        return metadata_dict

    except IOError as e:
        print(f"IOError: {e}")
        return None
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return None

def set_tower_managed_default(credential_type_name, user):
    try:
        from django.db import connection
        from django.db import IntegrityError

        if not isinstance(credential_type_name, str):
            raise TypeError("credential_type_name must be a string")

        credential_type_name = credential_type_name.strip()
        if not credential_type_name:
            raise ValueError("credential_type_name cannot be empty")

        if len(credential_type_name) > 255:
            raise ValueError("credential_type_name cannot exceed 255 characters")

        if not credential_type_name.isalnum():
            raise ValueError("credential_type_name must be alphanumeric")

        with connection.cursor() as cursor:
            try:
                cursor.execute(
                    """
                    INSERT INTO tower_credential_type (name, managed, auto_rotate, write_only, token_type, description)
                    VALUES (%s, TRUE, FALSE, FALSE, NULL, %s)
                    ON CONFLICT (name) DO NOTHING
                    """,
                    [credential_type_name, "Default Tower-Managed Credential"]
                )
            except IntegrityError:
                return 0

        return 1

    except (TypeError, ValueError) as e:
        print(f"Input validation error: {e}")
        return 0
    except Exception as e:
        print(f"Database error: {e}")
        return 0

