CREATE OR REPLACE FUNCTION create_row_level_triggers(
    target_table_name TEXT,
    trigger_function_name TEXT,
    trigger_event TEXT,
    trigger_condition TEXT DEFAULT 'TRUE',
    trigger_name_prefix TEXT DEFAULT 'row_level_'
)
RETURNS VOID
AS $$
DECLARE
    sql_statement TEXT;
    trigger_name TEXT;
    existing_trigger_name TEXT;
    sanitized_target_table_name TEXT;
    sanitized_trigger_function_name TEXT;
    sanitized_trigger_condition TEXT;
BEGIN
    -- Input Validation and Sanitization
    IF target_table_name IS NULL OR target_table_name = '' THEN
        RAISE EXCEPTION 'target_table_name cannot be null or empty.';
    END IF;

    IF trigger_function_name IS NULL OR trigger_function_name = '' THEN
        RAISE EXCEPTION 'trigger_function_name cannot be null or empty.';
    END IF;

    IF trigger_event IS NULL OR trigger_event = '' THEN
        RAISE EXCEPTION 'trigger_event cannot be null or empty.';
    END IF;

    IF trigger_event NOT IN ('BEFORE INSERT', 'AFTER INSERT', 'BEFORE UPDATE', 'AFTER UPDATE', 'BEFORE DELETE', 'AFTER DELETE') THEN
        RAISE EXCEPTION 'trigger_event must be one of: BEFORE INSERT, AFTER INSERT, BEFORE UPDATE, AFTER UPDATE, BEFORE DELETE, AFTER DELETE.';
    END IF;

    IF trigger_name_prefix IS NULL OR trigger_name_prefix = '' THEN
        trigger_name_prefix := 'row_level_';
    END IF;

    -- Sanitize inputs
    sanitized_target_table_name := quote_ident(target_table_name);
    sanitized_trigger_function_name := quote_ident(trigger_function_name);

    -- Validate trigger_condition - restrict to TRUE or FALSE
    IF trigger_condition NOT IN ('TRUE', 'FALSE') THEN
        RAISE EXCEPTION 'trigger_condition must be either TRUE or FALSE.';
    END IF;
    sanitized_trigger_condition := format('(%s)', trigger_condition);

    -- Drop existing triggers with the specified prefix
    DELETE FROM pg_trigger
    WHERE tgrelid = target_table_name::regclass
      AND tgname LIKE trigger_name_prefix || '%';

    -- Construct the trigger name
    trigger_name := trigger_name_prefix || trigger_function_name;

    -- Create the trigger
    sql_statement := format('CREATE TRIGGER %I
        ON %I
        %s
        FOR EACH ROW
        WHEN %s
        EXECUTE PROCEDURE %I();',
        trigger_name,
        sanitized_target_table_name,
        trigger_event,
        sanitized_trigger_condition,
        sanitized_trigger_function_name);

    EXECUTE sql_statement;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Error creating trigger: %', SQLERRM;
END;
$$ LANGUAGE plpgsql;

