class SecureDataRenderer:
    def __init__(self, train_file, val_file, test_file):
        self.train_file = train_file
        self.val_file = val_file
        self.test_file = test_file
        self.train_data = self._load_data(train_file)
        self.val_data = self._load_data(val_file)
        self.test_data = self._load_data(test_file)

    def _load_data(self, file_path):
        if not isinstance(file_path, str):
            raise TypeError("File path must be a string.")
        abs_path = os.path.abspath(file_path)
        allowed_dir = os.path.dirname(self.train_file)
        if not abs_path.startswith(allowed_dir):
            raise ValueError("Invalid file path: Path is outside the allowed directory.")

        try:
            with open(file_path, 'r') as f:
                data = json.load(f)
            return data
        except (json.JSONDecodeError, FileNotFoundError, OSError) as e:
            raise

    def render_data(self, dataset, output_zip_file):
        if dataset not in ['train', 'val', 'test']:
            raise ValueError("Dataset must be 'train', 'val', or 'test'.")
        if not isinstance(output_zip_file, str):
            raise TypeError("Output zip file must be a string.")

        data = None
        if dataset == 'train':
            data = self.train_data
        elif dataset == 'val':
            data = self.val_data
        else:
            data = self.test_data

        if data is None:
            raise ValueError(f"No data available for dataset: {dataset}")

        try:
            with zipfile.ZipFile(output_zip_file, 'w', zipfile.ZIP_DEFLATED) as zipf:
                for i, (image, label) in enumerate(data):
                    try:
                        if not isinstance(image, Image.Image):
                            raise TypeError("Image is not a PIL Image object.")
