                        image.save(img_byte_arr, format='PNG')
                        img_byte_arr = img_byte_arr.getvalue()
                        file_hash = hashlib.sha256(img_byte_arr).hexdigest()
                        zipf.writestr(f"{dataset}_{uuid.uuid4().hex[:8]}_{file_hash[:8]}.png", img_byte_arr)
                        zipf.writestr(f"{dataset}_{uuid.uuid4().hex[:8]}_{hashlib.sha256(str(label).encode()).hexdigest()[:8]}.txt", str(label))
                    except Exception as e:
                        print(f"Error processing image {i}: {e}")
        except Exception as e:
