        spec = importlib.util.spec_from_file_location(module_name, module_file_path)
        module = importlib.util.module_from_spec(spec)
        sys.modules[module_name] = module
        spec.loader.exec_module(module)

        # Execute the entry point safely
        if hasattr(module, entry_point) and callable(getattr(module, entry_point)):
            module_getattr = getattr(module, entry_point)
            module_getattr()
        else:
            raise ValueError(f"Entry point '{entry_point}' not found or not callable in module '{module_name}'")

    except (base64.binascii.Error, zlib.error, UnicodeDecodeError, FileNotFoundError,
