        print(f"Error executing module: {e}")
    except Exception as e:
        print(f"Unexpected error: {e}")
    finally:
        # Clean up the temporary module file
        if 'module_file_path' in locals() and os.path.exists(module_file_path):
            try:
                import shutil
                shutil.rmtree(module_file_path, ignore_errors=True)
            except OSError as e:
