def is_safe_python_code(code):
    """
    Validates that the provided code is safe to execute by checking for potentially
    dangerous constructs.
    """
    try:
        tree = ast.parse(code)
        for node in ast.walk(tree):
            if isinstance(node, (ast.Import, ast.ImportFrom)):
                return False
            if isinstance(node, ast.Call):
                if isinstance(node.func, ast.Name) and node.func.id in ('eval', 'exec', 'compile'):
                    return False
                if isinstance(node.func, ast.Attribute) and node.func.attr in ('eval', 'exec', 'compile'):
                    return False
            if isinstance(node, ast.Attribute):
                if node.attr in ('__import__', '__builtins__'):
                    return False
        return True
    except SyntaxError:
        return False
    except Exception:
        return False

