import logging

logging.basicConfig(level=logging.INFO)

class Sequencer:
    def __init__(self, name):
        self.name = name

    def process(self, data):
        """Simulates processing data."""
        return f"Sequencer {self.name} processed: {data}"

class System:
    def __init__(self, name):
        self.name = name

    def operate(self, command):
        """Simulates operating on a command."""
        return f"System {self.name} operating on: {command}"

class Controller:
    def __init__(self, controller_id, sequencer, system):
        self.controller_id = controller_id
        self.sequencer = sequencer
        self.system = system

    def execute(self, data, command):
        """Executes a sequence of operations."""
        try:
            sequencer_result = self.sequencer.process(data)
            system_result = self.system.operate(command)
            return f"Controller {self.controller_id}: {sequencer_result}, {system_result}"
        except Exception as e:
            logging.error(f"Controller {self.controller_id} execution failed: {e}")
            return f"Controller {self.controller_id}: Execution failed."

def create_controllers(controller_specs):
    """
    Creates a list of controller objects based on the provided specifications.

    Args:
        controller_specs (list): A list of dictionaries, where each dictionary
                                  specifies the type of controller, the number
                                  of instances to create, a sequencer name, and a system name.
                                  Example:
                                  [
                                      {'type': 'TypeA', 'count': 2, 'sequencer_name': 'Seq1', 'system_name': 'Sys1'},
                                      {'type': 'TypeB', 'count': 1, 'sequencer_name': 'Seq2', 'system_name': 'Sys2'}
                                  ]

    Returns:
        list: A list of Controller objects.  Returns an empty list if there are errors.
    """
    controllers = []
    if not isinstance(controller_specs, list):
        logging.error("Invalid input: controller_specs must be a list.")
        return []

    for spec in controller_specs:
        if not isinstance(spec, dict):
            logging.error("Invalid input: Each element in controller_specs must be a dictionary.")
            return []

        try:
            controller_type = spec.get('type')
            count = spec.get('count')
            if not isinstance(count, int):
                count = 0
            sequencer_name = spec.get('sequencer_name')
            system_name = spec.get('system_name')

            if not all([controller_type, sequencer_name, system_name]):
                logging.warning("Missing required parameters in controller specification.")
                continue

            sequencer = Sequencer(sequencer_name)
            system = System(system_name)

            for _ in range(count):
                controller_id = str(uuid.uuid4())
                controller = Controller(controller_id, sequencer, system)
                controllers.append(controller)

        except (TypeError, ValueError) as e:
            logging.error(f"Error processing controller specification: {e}")
            return []
        except Exception as e:
            logging.error(f"Unexpected error: {e}")
            return []

    return controllers

import re

def get_table_columns(cursor, table_name, columns=None, named_tuples=False):
    """
    Retrieves the columns of a specific table from the database.

    Args:
        cursor: A database cursor object.
        table_name: The name of the table to retrieve columns from.
        columns: An optional list of column names to retrieve. If None, all columns are retrieved.
        named_tuples: An optional boolean indicating whether to return the results as named tuples.

    Returns:
        A list of tuples or named tuples, where each tuple/named tuple contains the column name and data type.
        Returns an empty list if the table does not exist or an error occurs.
    """

    if not isinstance(cursor, (type(None), object)):
        raise TypeError("Cursor must be a database cursor object.")

    if not isinstance(table_name, str):
        raise TypeError("Table name must be a string.")

    if not re.match(r"^[a-zA-Z_][a-zA-Z0-9_]*$", table_name):
        raise ValueError("Invalid table name. Table names must start with a letter or underscore and contain only alphanumeric characters and underscores.")

    if columns is not None:
        if not isinstance(columns, list):
            raise TypeError("Columns must be a list.")
        for col in columns:
            if not isinstance(col, str):
                raise TypeError("Column names must be strings.")
            if not re.match(r"^[a-zA-Z_][a-zA-Z0-9_]*$", col):
                raise ValueError("Invalid column name. Column names must start with a letter or underscore and contain only alphanumeric characters and underscores.")

    try:
        if columns:
            query = f"SHOW COLUMNS FROM `{table_name}` WHERE Field IN ({', '.join(['%s'] * len(columns))})"
            cursor.execute(query, columns)
        else:
            query = f"SHOW COLUMNS FROM `{table_name}`"
            cursor.execute(query)
        results = cursor.fetchall()

        if named_tuples:
            from collections import namedtuple
            Column = namedtuple('Column', ['Field', 'Type', 'Null', 'Key', 'Default', 'Extra'])
            return [Column(row[0], row[1], row[2], row[3], row[4], row[5]) for row in results]
        else:
            return [(row[0], row[1]) for row in results]

    except Exception as e:
        # Log the error securely (without sensitive data)
        print(f"Error retrieving table columns: {type(e).__name__}")
        return []

