logging.basicConfig(level=logging.ERROR)

def load_and_execute_extension(extension_file, base_pythonpath, root_directory):
    """
    Loads a custom environment extension from a file and executes it,
    extending a given PythonPath object with the extension's functionality.

    Args:
        extension_file (str): The path to the extension file.
        base_pythonpath (object): The base PythonPath object to extend.
        root_directory (str): The root directory to pass to the extension.

    Returns:
        object: The extended PythonPath object, or None if an error occurred.
    """
    try:
        if not isinstance(extension_file, str):
            raise TypeError("extension_file must be a string")
        if not isinstance(base_pythonpath, object):
            raise TypeError("base_pythonpath must be an object")
        if not isinstance(root_directory, str):
            raise TypeError("root_directory must be a string")

        if not os.path.isfile(extension_file):
            raise FileNotFoundError(f"Extension file not found: {extension_file}")

        extension_file = os.path.abspath(extension_file)
        if not extension_file.startswith(os.path.abspath('.')):
            raise ValueError("Extension file path is not within the current directory.")

        with open(extension_file, 'r') as f:
            source_code = f.read()

        # Security check: Disallow potentially dangerous constructs
        for construct in ['import', 'exec', 'eval', 'open', 'subprocess']:
            if construct in source_code:
                raise ValueError(f"Extension contains potentially dangerous construct: {construct}")

        # Parse the AST to further restrict allowed nodes
        try:
            tree = ast.parse(source_code)
            for node in ast.walk(tree):
                if isinstance(node, (ast.Import, ast.ImportFrom, ast.Call, ast.Attribute)):
                    raise ValueError("Extension contains potentially dangerous constructs.")
        except SyntaxError as e:
            raise ValueError(f"Invalid extension syntax: {e}")

        spec = importlib.util.spec_from_file_location("extension", extension_file)
        if spec is None:
            raise ValueError(f"Could not create module spec for {extension_file}")

        module = importlib.util.module_from_spec(spec)
        sys.modules["extension"] = module
        try:
            spec.loader.exec_module(module)
        except Exception as e:
            logging.error(f"Error executing extension module: {e}")
            traceback.print_exc()
            return None

        if not hasattr(module, "Extend"):
            raise ValueError("Extension module must define an 'Extend' function.")

        extend_function = getattr(module, "Extend")

        if not callable(extend_function):
            raise TypeError("The 'Extend' function must be callable.")

        # Sanitize root_directory
        if not isinstance(root_directory, str):
            raise TypeError("root_directory must be a string")
        root_directory = os.path.abspath(root_directory)
        if not root_directory.startswith(os.path.abspath('.')):
            raise ValueError("root_directory is not within the current directory.")

        try:
            extended_pythonpath = extend_function(base_pythonpath, root_directory)
            if not isinstance(extended_pythonpath, object):
                raise TypeError("Extend function must return an object.")
            return extended_pythonpath
        except Exception as e:
            logging.error(f"Error calling 'Extend' function: {e}")
            traceback.print_exc()
            return None

    except (TypeError, FileNotFoundError, ValueError, Exception) as e:
        logging.error(f"Error loading and executing extension: {e}")
        traceback.print_exc()
        return None

import json
import logging

def deserialize_json_safely(json_string, object_keys_allowed=False):
    """
    Deserializes a JSON string into a Python object, with optional decoding of
    dictionary keys into Python objects.

    Args:
        json_string (str): The JSON string to deserialize.
        object_keys_allowed (bool, optional): Whether to allow dictionary keys
            to be decoded into Python objects. Defaults to False.

    Returns:
        object: The deserialized Python object, or None if deserialization fails.
    """
    if not isinstance(json_string, str):
        logging.error("Input must be a string.")
        return None

    try:
        if object_keys_allowed:
            return json.loads(json_string, object_hook=object_hook)
        else:
            return json.loads(json_string)
    except (json.JSONDecodeError, TypeError) as e:
        logging.error(f"Failed to deserialize JSON: {e}")
        return None

def object_hook(data):
    """
    Custom object hook for json.loads to handle non-string keys.
    """
    if isinstance(data, dict):
        allowed_keys = {str, int, float, bool}
        return {k: v for k, v in data.items() if isinstance(k, allowed_keys)}
    return data

