class AudioBookPlayerController:
    def __init__(self, db_config_file="db_config.json"):
        try:
            if not os.path.isfile(db_config_file):
                raise FileNotFoundError
            with open(db_config_file, 'r') as f:
                db_config = json.load(f)
            self.db_handler = database_handler.DatabaseHandler(**db_config)
            self.player = audiobook_player.AudioBookPlayer()
            self.rfid_reader_instance = rfid_reader.RFIDReader()
        except FileNotFoundError:
            logging.error(f"Database configuration file not found: {db_config_file}")
            sys.exit(1)
        except json.JSONDecodeError:
            logging.error(f"Invalid JSON format in database configuration file: {db_config_file}")
            sys.exit(1)
        except Exception as e:
            logging.error(f"Error initializing components: {e}")
            sys.exit(1)

    def process_rfid(self):
        try:
            rfid_tag_id = self.rfid_reader_instance.read_rfid()
            if rfid_tag_id:
                rfid_tag_id = self.rfid_reader_instance.sanitize_rfid(rfid_tag_id)
                if not rfid_tag_id:
                    logging.warning("Invalid RFID tag ID received.")
                    return

                book_info = self.db_handler.get_book_by_rfid(rfid_tag_id)
                if book_info:
                    book_title = book_info['title']
                    book_file_path = book_info['file_path']
                    user_id = book_info['user_id']

                    if self.player.is_playing():
                        self.player.stop()

                    audiobook_dir = "audiobooks"  # Define a safe directory
                    if not os.path.exists(audiobook_dir):
                        os.makedirs(audiobook_dir)

                    full_book_file_path = os.path.abspath(os.path.join(audiobook_dir, book_file_path))

                    if not full_book_file_path.startswith(os.path.abspath(audiobook_dir)):
                        logging.error(f"Invalid file path: {book_file_path}")
                        return

                    self.player.start(full_book_file_path)
                    self.player.set_user_id(user_id)
                    self.player.set_book_title(book_title)
                    self.db_handler.update_playing_status(user_id, True)
                    logging.info(f"Started playing '{book_title}' for user {user_id}")
                else:
                    logging.warning(f"No book found for RFID tag ID: {rfid_tag_id}")
            else:
                logging.debug("No RFID tag detected.")
        except Exception as e:
            logging.error(f"Error processing RFID: {e}")

    def check_playback_finished(self):
        try:
            if self.player.is_playing():
                if self.player.has_finished():
                    user_id = self.player.get_user_id()
                    book_title = self.player.get_book_title()
                    self.player.stop()
                    self.db_handler.update_playing_status(user_id, False)
                    self.db_handler.delete_progress(user_id)
                    logging.info(f"Finished playing '{book_title}' for user {user_id}. Progress deleted.")
        except Exception as e:
            logging.error(f"Error checking playback finished: {e}")

    def run(self):
        try:
            while True:
                self.process_rfid()
                self.check_playback_finished()
                # Add a small delay to avoid excessive CPU usage
                import time
                time.sleep(1)
        except KeyboardInterrupt:
            logging.info("Exiting program.")
        except Exception as e:
            logging.error(f"Unhandled error in main loop: {e}")
        finally:
            self.player.stop()
            self.db_handler.close_connection()


