def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

MIME_TYPES = {
    'txt': 'text/plain',
    'pdf': 'application/pdf',
    'csv': 'text/csv'
}

def get_mime_type(filename):
    ext = filename.rsplit('.', 1)[1].lower()
    return MIME_TYPES.get(ext, 'application/octet-stream')

@app.route('/', methods=['GET', 'POST'])
def upload_file():
    if request.method == 'POST':
        if 'file' not in request.files:
            return render_template('index.html', error='No file part')

        file = request.files['file']
        user_param = request.form.get('user_param', '')

        if file.filename == '':
            return render_template('index.html', error='No file selected')

        if not allowed_file(file.filename):
            return render_template('index.html', error='Invalid file type')

        try:
            # Sanitize user input
            user_param = CTk.sanitize_string(user_param)

            # Generate a secure filename
            filename = hashlib.sha256(file.read()).hexdigest() + os.path.splitext(file.filename)[1]

            # Path sanitization
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            filepath = os.path.abspath(filepath)
            if not filepath.startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
                return render_template('index.html', error='Invalid file path')

            file.save(filepath)

            # Process the file (example: calculate file size)
            file_size = os.path.getsize(filepath)

            # Log the upload event
            app.logger.info(f"File '{filename}' uploaded by user with parameter '{user_param}'")

            return render_template('result.html', filename=filename, user_param=user_param)

        except Exception as e:
            app.logger.error(f"Error processing file: {e}")
            return render_template('index.html', error=f'An error occurred: {str(e)}')

    return render_template('index.html')

@app.route('/uploads/<filename>')
def download_file(filename):
    try:
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        filepath = os.path.abspath(filepath)
        if not filepath.startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
            return "File not found", 404

        if os.path.exists(filepath):
            return send_file(filepath, mimetype=get_mime_type(filename), as_attachment=True)
        else:
            return "File not found", 404
    except Exception as e:
        app.logger.error(f"Error downloading file: {e}")
        return "File not found", 404

