import java.io.BufferedReader;
import java.io.File;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.io.StringReader;
import java.io.UnsupportedEncodingException;
import java.net.URLEncoder;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.regex.Pattern;

public class AntlrRunner {

    public static void main(String[] args) {
        if (args.length < 3) {
            System.err.println("Usage: java AntlrRunner <antlr_path> <grammar_directory> <grammar_file> [options]");
            System.exit(1);
        }

        String antlrPath = args[0];
        String grammarDirectory = args[1];
        String grammarFile = args[2];
        List<String> options = new ArrayList<>();

        if (args.length > 3) {
            options.addAll(Arrays.asList(args[3]));
        }

        try {
            runAntlr(antlrPath, grammarDirectory, grammarFile, options);
        } catch (IOException e) {
            System.err.println("Error running ANTLR: " + e.getMessage());
            System.exit(1);
        }
    }

    private static void runAntlr(String antlrPath, String grammarDirectory, String grammarFile, List<String> options) throws IOException {
        // Validate inputs
        if (antlrPath == null || antlrPath.trim().isEmpty()) {
            throw new IllegalArgumentException("ANTLR path cannot be null or empty.");
        }
        if (grammarDirectory == null || grammarDirectory.trim().isEmpty()) {
            throw new IllegalArgumentException("Grammar directory cannot be null or empty.");
        }
        if (grammarFile == null || grammarFile.trim().isEmpty()) {
            throw new IllegalArgumentException("Grammar file cannot be null or empty.");
        }

        File dir = new File(grammarDirectory);
        if (!dir.exists() || !dir.isDirectory()) {
            throw new IllegalArgumentException("Grammar directory does not exist or is not a directory.");
        }

        String canonicalGrammarDirectory = dir.getCanonicalPath();

        // Construct the command
        List<String> command = new ArrayList<>();
        command.add(antlrPath);

        for (String option : options) {
            if (isValidOption(option)) {
                command.add(option);
            } else {
                throw new IllegalArgumentException("Invalid option: " + option);
            }
        }

        command.add("-DerrorNoSynonym=8"); // Suppress noisy warnings
        command.add(canonicalGrammarDirectory + File.separator + grammarFile);

        // Use ProcessBuilder
        ProcessBuilder processBuilder = new ProcessBuilder(command);
        processBuilder.redirectErrorStream(true); // Redirect stderr to stdout

        Process process = processBuilder.start();

        // Capture output
        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        PrintWriter writer = new PrintWriter(System.out);

        String line;
        while ((line = reader.readLine()) != null) {
            writer.println(line);
        }

        int exitCode = process.waitFor();

        if (exitCode != 0) {
            System.err.println("ANTLR tool exited with error code: " + exitCode);
        }
    }

    private static boolean isValidOption(String option) {
        Pattern pattern = Pattern.compile("^([a-zA-Z0-9_]+)=(?:[a-zA-Z0-9._-]+)$");
        return pattern.matcher(option).matches();
    }
}

