import requests
import json
import logging
from urllib.parse import urljoin

def update_asset_type(api_url, asset_type_id, updated_asset_type_data, verify_ssl=True):
    try:
        if not isinstance(api_url, str) or not api_url:
            raise ValueError("API URL must be a non-empty string.")
        if not isinstance(asset_type_id, str) or not asset_type_id:
            raise ValueError("Asset type ID must be a non-empty string.")
        if not isinstance(updated_asset_type_data, dict):
            raise ValueError("Updated asset type data must be a dictionary.")

        url = urljoin(api_url, f"/asset_types/{asset_type_id}")

        sanitized_data = {}
        for key, value in updated_asset_type_data.items():
            if key not in ["name", "description"]:
                logging.warning(f"Ignoring potentially unsafe key: {key}")
                continue
            if key == "name":
                if not isinstance(value, str) or len(value) > 255:
                    logging.warning(f"Invalid name length: {len(value)}")
                    continue
                sanitized_data[key] = value
            elif key == "description":
                if not isinstance(value, str) or len(value) > 1000:
                    logging.warning(f"Invalid description length: {len(value)}")
                    continue
                sanitized_data[key] = value

        try:
            response = requests.put(url, json=sanitized_data, verify=verify_ssl, timeout=10)
            response.raise_for_status()
        except requests.exceptions.RequestException as e:
            logging.error(f"Request failed: {e}")
            return None

        try:
            response_data = response.json()
        except json.JSONDecodeError:
            logging.error(f"Failed to decode JSON response: {response.text}")
            return None

        if "message" in response_data and "Asset type updated successfully" in response_data["message"]:
            return response_data
        else:
            logging.warning(f"Unexpected response: {response_data}")
            return response_data

    except ValueError as e:
        logging.error(f"Invalid input: {e}")
        return None
    except Exception as e:
        logging.exception(f"An unexpected error occurred: {e}")
        return None
